{
  "name": "Echo - The AI Social Experiment",
  "description": "A single-page social experience where you interact with a simulated community generated by Gemini. Posts are persisted locally, and the 'network' reacts to you in real-time."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface User {
  nickname: string;
  avatarSeed: string; // For generating consistent avatars
  isAi: boolean;
}

export interface Comment {
  id: string;
  author: User;
  content: string;
  timestamp: number;
  likes: number;
}

export interface Post {
  id: string;
  author: User;
  content: string;
  tags: string[];
  timestamp: number;
  likes: number;
  comments: Comment[];
}

export enum SimulationEventType {
  NEW_POST = 'NEW_POST',
  REACTION = 'REACTION',
  TRENDING_UPDATE = 'TRENDING_UPDATE'
}

export interface SimulationResponse {
  newPosts?: Array<{
    authorName: string;
    content: string;
    tags: string[];
  }>;
  reactionsToPost?: {
    postId: string;
    comments: Array<{
      authorName: string;
      content: string;
    }>;
    likesToAdd: number;
  };
  trendingTopics?: string[];
}

export const LOCAL_STORAGE_KEY = 'echo_app_state_v1';
export const MAX_POSTS_IN_MEMORY = 50;

export const DEFAULT_AVATAR_URL = (seed: string) => `https://api.dicebear.com/7.x/notionists/svg?seed=${seed}&backgroundColor=b6e3f4,c0aede,d1d4f9`;

export const INITIAL_TOPICS = ['#WelcomeToEcho', '#AIExperiment', '#DigitalVoid'];

export const SYSTEM_INSTRUCTION = `
You are the engine of "Echo", a simulated social network. 
Your goal is to make the user feel like they are in a bustling, diverse online community.
You will generate content for "other users" (AI agents) in response to the real user's activity or just as background noise.

Rules for content generation:
1.  **Diversity**: Use varied personas (techies, artists, shitposters, philosophizers, bots).
2.  **Realism**: Include typos, slang, hashtags, and varying sentence structures.
3.  **Context**: If the user posts about a specific topic, generate replies or new posts related to that topic.
4.  **Tags**: Always include 1-3 relevant hashtags for posts.
5.  **Output**: strictly return JSON matching the schema provided.
`;

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { Post, SimulationResponse } from "../types";

// Initialize Gemini Client
// Assumption: process.env.API_KEY is available.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Schema for the simulation response
const simulationSchema = {
  type: Type.OBJECT,
  properties: {
    newPosts: {
      type: Type.ARRAY,
      description: "Generate 0-2 new background posts from other users to keep the feed alive.",
      items: {
        type: Type.OBJECT,
        properties: {
          authorName: { type: Type.STRING },
          content: { type: Type.STRING },
          tags: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["authorName", "content", "tags"]
      }
    },
    reactionsToPost: {
      type: Type.OBJECT,
      description: "If the user just posted, generate reactions (comments/likes) to it. Otherwise null.",
      properties: {
        postId: { type: Type.STRING, description: "The ID of the user's post being reacted to." },
        likesToAdd: { type: Type.INTEGER, description: "Number of likes to add (0-20)" },
        comments: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              authorName: { type: Type.STRING },
              content: { type: Type.STRING }
            },
            required: ["authorName", "content"]
          }
        }
      },
      nullable: true
    },
    trendingTopics: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "List of 5 currently trending hashtags based on the conversation context."
    }
  },
  required: ["trendingTopics"]
};

export const simulateSocialActivity = async (
  currentPosts: Post[], 
  latestUserPost: Post | null
): Promise<SimulationResponse> => {
  try {
    const model = "gemini-2.5-flash";

    // Prepare context for the model
    const context = `
      Current Feed Context (Last 5 posts):
      ${JSON.stringify(currentPosts.slice(0, 5).map(p => ({ 
        author: p.author.nickname, 
        content: p.content, 
        tags: p.tags 
      })))}

      ${latestUserPost 
        ? `ACTION REQUIRED: The user (${latestUserPost.author.nickname}) just posted: "${latestUserPost.content}". ID: ${latestUserPost.id}. Generate reactions specifically for this.` 
        : `ACTION: No new user post. Just generate ambient background activity (1-2 new posts from others).`
      }
    `;

    const response = await ai.models.generateContent({
      model,
      contents: context,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: simulationSchema,
        temperature: 1.2, // High creativity for diverse personas
      }
    });

    if (!response.text) {
      throw new Error("Empty response from Gemini");
    }

    return JSON.parse(response.text) as SimulationResponse;

  } catch (error) {
    console.error("Gemini Simulation Error:", error);
    // Fallback safe response
    return {
      trendingTopics: ["#Error", "#SystemGlitch"],
      newPosts: []
    };
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {
  const baseStyles = "px-4 py-2 rounded-lg font-medium transition-all duration-200 flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-500/20 border border-blue-500/50",
    secondary: "bg-slate-700 hover:bg-slate-600 text-slate-100 border border-slate-600",
    ghost: "bg-transparent hover:bg-slate-800 text-slate-400 hover:text-white"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <>
          <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Processing...
        </>
      ) : children}
    </button>
  );
};

import React, { useState } from 'react';
import { Heart, MessageCircle, Share2, MoreHorizontal } from 'lucide-react';
import { Post, Comment } from '../types';
import { DEFAULT_AVATAR_URL } from '../constants';

interface PostCardProps {
  post: Post;
  isUser: boolean;
}

export const PostCard: React.FC<PostCardProps> = ({ post, isUser }) => {
  const [liked, setLiked] = useState(false);
  const [likeCount, setLikeCount] = useState(post.likes);

  const handleLike = () => {
    if (liked) {
      setLikeCount(prev => prev - 1);
    } else {
      setLikeCount(prev => prev + 1);
    }
    setLiked(!liked);
  };

  const formattedTime = new Intl.DateTimeFormat('en-US', {
    hour: 'numeric',
    minute: 'numeric',
  }).format(new Date(post.timestamp));

  return (
    <div className={`
      relative p-5 rounded-xl border mb-4 transition-all duration-300
      ${isUser ? 'bg-blue-900/10 border-blue-500/30' : 'bg-slate-800/40 border-slate-700/50'}
      hover:border-slate-600 hover:shadow-lg hover:shadow-black/20
    `}>
      {/* Header */}
      <div className="flex items-start justify-between mb-3">
        <div className="flex items-center gap-3">
          <img 
            src={DEFAULT_AVATAR_URL(post.author.avatarSeed)} 
            alt={post.author.nickname}
            className="w-10 h-10 rounded-full bg-slate-700 ring-2 ring-slate-800"
          />
          <div>
            <div className="flex items-center gap-2">
              <span className={`font-semibold ${isUser ? 'text-blue-400' : 'text-slate-200'}`}>
                {post.author.nickname}
              </span>
              {post.author.isAi && (
                <span className="text-[10px] px-1.5 py-0.5 rounded bg-slate-700 text-slate-400 font-mono">
                  BOT
                </span>
              )}
            </div>
            <span className="text-xs text-slate-500">{formattedTime}</span>
          </div>
        </div>
        <button className="text-slate-500 hover:text-slate-300">
          <MoreHorizontal size={18} />
        </button>
      </div>

      {/* Content */}
      <div className="mb-4">
        <p className="text-slate-300 whitespace-pre-wrap leading-relaxed">
          {post.content}
        </p>
        {post.tags.length > 0 && (
          <div className="flex flex-wrap gap-2 mt-3">
            {post.tags.map(tag => (
              <span key={tag} className="text-xs font-medium text-blue-400/80 hover:text-blue-400 cursor-pointer">
                #{tag.replace('#', '')}
              </span>
            ))}
          </div>
        )}
      </div>

      {/* Actions */}
      <div className="flex items-center justify-between pt-3 border-t border-slate-700/50">
        <button 
          onClick={handleLike}
          className={`flex items-center gap-1.5 text-sm font-medium transition-colors ${liked ? 'text-pink-500' : 'text-slate-400 hover:text-pink-500'}`}
        >
          <Heart size={18} fill={liked ? "currentColor" : "none"} />
          <span>{likeCount}</span>
        </button>

        <button className="flex items-center gap-1.5 text-sm font-medium text-slate-400 hover:text-blue-400 transition-colors">
          <MessageCircle size={18} />
          <span>{post.comments.length}</span>
        </button>

        <button className="flex items-center gap-1.5 text-sm font-medium text-slate-400 hover:text-green-400 transition-colors">
          <Share2 size={18} />
        </button>
      </div>

      {/* Comments Preview */}
      {post.comments.length > 0 && (
        <div className="mt-4 space-y-3 pl-4 border-l-2 border-slate-700">
          {post.comments.map(comment => (
            <div key={comment.id} className="flex gap-2">
              <img 
                src={DEFAULT_AVATAR_URL(comment.author.avatarSeed)} 
                alt={comment.author.nickname}
                className="w-6 h-6 rounded-full bg-slate-700"
              />
              <div className="bg-slate-800/50 rounded-lg rounded-tl-none p-2 flex-1">
                <div className="flex items-center justify-between mb-1">
                  <span className="text-xs font-semibold text-slate-300">{comment.author.nickname}</span>
                  <span className="text-[10px] text-slate-500">just now</span>
                </div>
                <p className="text-xs text-slate-400">{comment.content}</p>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Send, Hash, Sparkles } from 'lucide-react';
import { Button } from './Button';

interface CreatePostProps {
  onPost: (nickname: string, content: string, tags: string[]) => void;
  defaultNickname: string;
}

export const CreatePost: React.FC<CreatePostProps> = ({ onPost, defaultNickname }) => {
  const [nickname, setNickname] = useState(defaultNickname);
  const [content, setContent] = useState('');
  const [tagInput, setTagInput] = useState('');
  const [isFocused, setIsFocused] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!nickname.trim() || !content.trim()) return;

    // Parse tags from input or find in content
    const tags = tagInput.split(' ').filter(t => t.startsWith('#')).map(t => t.replace('#', ''));
    // Auto-detect tags in content if none provided
    const contentTags = content.match(/#[\w]+/g)?.map(t => t.replace('#', '')) || [];
    const finalTags = [...new Set([...tags, ...contentTags])];

    onPost(nickname, content, finalTags);
    setContent('');
    setTagInput('');
  };

  return (
    <div className="bg-slate-800/40 backdrop-blur-xl border border-slate-700/50 rounded-xl p-4 mb-6 shadow-xl relative overflow-hidden group">
        {/* Glow effect */}
        <div className="absolute inset-0 bg-gradient-to-r from-blue-500/5 to-purple-500/5 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" />

      <form onSubmit={handleSubmit}>
        <div className="flex gap-3 mb-3">
            <div className="relative">
                <input
                    type="text"
                    value={nickname}
                    onChange={(e) => setNickname(e.target.value)}
                    placeholder="Nickname"
                    className="bg-slate-900/50 border border-slate-700 rounded-lg px-3 py-1.5 text-sm text-blue-300 placeholder-slate-500 focus:outline-none focus:border-blue-500/50 focus:ring-1 focus:ring-blue-500/50 w-32 font-mono"
                    required
                />
            </div>
            <div className="flex-1" />
        </div>

        <div className="relative">
          <textarea
            value={content}
            onChange={(e) => setContent(e.target.value)}
            onFocus={() => setIsFocused(true)}
            onBlur={() => setIsFocused(false)}
            placeholder="What's on your mind?"
            className="w-full bg-transparent border-none text-slate-200 placeholder-slate-500 focus:ring-0 resize-none min-h-[80px] text-lg p-0"
            required
          />
        </div>

        <div className={`transition-all duration-300 overflow-hidden ${isFocused || content ? 'max-h-20 opacity-100 mt-3' : 'max-h-0 opacity-0'}`}>
          <div className="flex items-center gap-2">
            <Hash size={16} className="text-slate-500" />
            <input
              type="text"
              value={tagInput}
              onChange={(e) => setTagInput(e.target.value)}
              placeholder="Add tags (e.g. #random #thought)"
              className="bg-transparent border-none text-sm text-blue-400 placeholder-slate-600 focus:ring-0 flex-1 p-0"
            />
          </div>
        </div>

        <div className="flex justify-between items-center mt-4 pt-3 border-t border-slate-700/30">
          <div className="flex gap-2">
             <button type="button" className="p-2 hover:bg-slate-700 rounded-full text-slate-400 hover:text-blue-400 transition-colors" title="AI Assist (Decoration)">
                <Sparkles size={18} />
             </button>
          </div>
          <Button type="submit" disabled={!content.trim() || !nickname.trim()}>
            <span>Post</span>
            <Send size={16} />
          </Button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Sidebar } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { simulateSocialActivity } from './services/gemini';
import { Post, User, SimulationResponse } from './types';
import { LOCAL_STORAGE_KEY, INITIAL_TOPICS, MAX_POSTS_IN_MEMORY } from './constants';
import { v4 as uuidv4 } from 'uuid';

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);
  const [currentUserNickname, setCurrentUserNickname] = useState<string>('Guest');
  const [trendingTopics, setTrendingTopics] = useState<string[]>(INITIAL_TOPICS);
  const [isSimulating, setIsSimulating] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Load initial state
  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setPosts(parsed.posts || []);
        setCurrentUserNickname(parsed.nickname || 'Guest');
      } catch (e) {
        console.error("Failed to load local storage", e);
      }
    }
  }, []);

  // Save state
  useEffect(() => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      posts: posts.slice(0, MAX_POSTS_IN_MEMORY), // Keep storage clean
      nickname: currentUserNickname
    }));
  }, [posts, currentUserNickname]);

  // Helper to add post safely
  const addPost = useCallback((post: Post) => {
    setPosts(prev => [post, ...prev]);
  }, []);

  // The Engine: Handle Gemini Simulation
  const runSimulation = async (triggerPost: Post | null) => {
    setIsSimulating(true);

    // Slight delay to make it feel like "processing" network request
    if (triggerPost) await new Promise(r => setTimeout(r, 800));

    const simulationResult: SimulationResponse = await simulateSocialActivity(posts, triggerPost);

    // Apply simulation results

    // 1. Add reactions to user post (if any)
    if (simulationResult.reactionsToPost && triggerPost) {
       setPosts(currentPosts => currentPosts.map(p => {
          if (p.id === triggerPost.id) {
             const newComments = simulationResult.reactionsToPost!.comments.map(c => ({
                id: uuidv4(),
                author: { nickname: c.authorName, isAi: true, avatarSeed: c.authorName },
                content: c.content,
                timestamp: Date.now(),
                likes: Math.floor(Math.random() * 5)
             }));
             return {
                ...p,
                likes: p.likes + (simulationResult.reactionsToPost!.likesToAdd || 0),
                comments: [...newComments, ...p.comments]
             };
          }
          return p;
       }));
    }

    // 2. Add new ambient posts
    if (simulationResult.newPosts && simulationResult.newPosts.length > 0) {
        const newAiPosts: Post[] = simulationResult.newPosts.map(p => ({
            id: uuidv4(),
            author: { nickname: p.authorName, isAi: true, avatarSeed: p.authorName },
            content: p.content,
            tags: p.tags,
            timestamp: Date.now(),
            likes: Math.floor(Math.random() * 20),
            comments: []
        }));

        // Add them one by one with slight stagger for effect
        newAiPosts.forEach((p, index) => {
            setTimeout(() => {
                addPost(p);
            }, index * 2000 + 1000); // Stagger
        });
    }

    // 3. Update Trending
    if (simulationResult.trendingTopics && simulationResult.trendingTopics.length > 0) {
        setTrendingTopics(simulationResult.trendingTopics);
    }

    setIsSimulating(false);
  };

  const handleUserPost = (nickname: string, content: string, tags: string[]) => {
    setCurrentUserNickname(nickname);

    const newPost: Post = {
      id: uuidv4(),
      author: { nickname, isAi: false, avatarSeed: nickname },
      content,
      tags,
      timestamp: Date.now(),
      likes: 0,
      comments: []
    };

    addPost(newPost);

    // Trigger the simulation engine
    runSimulation(newPost);
  };

  // Ambient activity effect: If no posts for a while, generate something
  useEffect(() => {
      const interval = setInterval(() => {
          const lastPostTime = posts.length > 0 ? posts[0].timestamp : 0;
          const now = Date.now();
          // If silence for 45 seconds, poke the bear
          if (now - lastPostTime > 45000 && !isSimulating) {
              console.log("Feed silent, generating ambient noise...");
              runSimulation(null);
          }
      }, 10000); // Check every 10s

      return () => clearInterval(interval);
  }, [posts, isSimulating]);


  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 selection:bg-blue-500/30">

      {/* Background Ambience */}
      <div className="fixed inset-0 z-0 pointer-events-none">
        <div className="absolute top-[-10%] right-[-5%] w-[500px] h-[500px] bg-blue-600/10 rounded-full blur-[128px]" />
        <div className="absolute bottom-[-10%] left-[-5%] w-[500px] h-[500px] bg-purple-600/10 rounded-full blur-[128px]" />
      </div>

      <div className="relative z-10 max-w-6xl mx-auto flex gap-6 px-4 py-6 h-screen overflow-hidden">

        {/* Left Sidebar - Navigation/Info */}
        <aside className="hidden lg:flex flex-col w-64 shrink-0 gap-6">
          <div className="p-4 rounded-xl bg-slate-800/20 border border-slate-700/50 backdrop-blur-md">
            <h1 className="text-2xl font-bold bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent mb-2">
              Echo
            </h1>
            <p className="text-sm text-slate-400 leading-relaxed">
              A decentralized social experiment. Posts here are broadcast into the void, where the network reacts.
            </p>
          </div>

          <div className="flex-1 p-4 rounded-xl bg-slate-800/20 border border-slate-700/50 backdrop-blur-md">
            <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4">Trending</h3>
            <div className="flex flex-col gap-3">
              {trendingTopics.map((topic, i) => (
                <div key={i} className="group cursor-pointer">
                    <span className="text-slate-300 font-medium group-hover:text-blue-400 transition-colors">{topic}</span>
                    <div className="text-xs text-slate-600">{Math.floor(Math.random() * 1000) + 100} posts</div>
                </div>
              ))}
            </div>
          </div>
        </aside>

        {/* Main Feed */}
        <main className="flex-1 flex flex-col h-full max-w-2xl mx-auto w-full">
          {/* Header for Mobile */}
          <div className="lg:hidden mb-4 flex items-center justify-between">
             <h1 className="text-xl font-bold text-blue-400">Echo</h1>
             <div className="text-xs px-2 py-1 bg-blue-500/10 text-blue-400 rounded-full border border-blue-500/20">
                Live Simulation
             </div>
          </div>

          <CreatePost onPost={handleUserPost} defaultNickname={currentUserNickname} />

          {/* Feed List */}
          <div 
            ref={scrollRef}
            className="flex-1 overflow-y-auto pr-2 pb-20 scroll-smooth"
          >
            {posts.length === 0 ? (
                <div className="text-center py-20 text-slate-500">
                    <div className="text-6xl mb-4 opacity-20">📡</div>
                    <p className="text-lg">The signal is quiet.</p>
                    <p className="text-sm">Be the first to broadcast.</p>
                </div>
            ) : (
                <>
                    {posts.map(post => (
                        <PostCard 
                            key={post.id} 
                            post={post} 
                            isUser={post.author.nickname === currentUserNickname && !post.author.isAi} 
                        />
                    ))}
                    <div className="h-10 flex items-center justify-center text-slate-600 text-sm">
                        {isSimulating ? (
                            <span className="animate-pulse flex items-center gap-2">
                                <span className="w-2 h-2 bg-blue-500 rounded-full"></span>
                                Network is reacting...
                            </span>
                        ) : (
                            <span>End of stream</span>
                        )}
                    </div>
                </>
            )}
          </div>
        </main>

        {/* Right Sidebar - Active Users (Fake) */}
        <aside className="hidden xl:block w-72 shrink-0">
             <div className="p-4 rounded-xl bg-slate-800/20 border border-slate-700/50 backdrop-blur-md sticky top-6">
                <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                    <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
                    Online Nodes
                </h3>
                <div className="space-y-4">
                    {[1,2,3,4,5].map((_, i) => (
                        <div key={i} className="flex items-center gap-3 opacity-60 hover:opacity-100 transition-opacity cursor-pointer">
                            <div className="w-8 h-8 rounded-full bg-slate-700 overflow-hidden">
                                <img src={`https://api.dicebear.com/7.x/notionists/svg?seed=user${i}&backgroundColor=transparent`} alt="User" />
                            </div>
                            <div>
                                <div className="text-sm font-medium text-slate-300">User_{Math.floor(Math.random() * 9999)}</div>
                                <div className="text-xs text-slate-500">Browsing...</div>
                            </div>
                        </div>
                    ))}
                </div>
             </div>
        </aside>

      </div>
    </div>
  );
}

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost' | 'fab';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {
  // M3 Base: 40px height, rounded-full, font-medium tracking-wide
  const baseStyles = "h-10 px-6 rounded-full font-medium text-sm tracking-wide transition-all duration-200 flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed active:scale-[0.98]";

  const variants = {
    // Primary: Indigo 400 bg, Indigo 950 text
    primary: "bg-indigo-400 hover:bg-indigo-300 text-indigo-950 shadow-sm hover:shadow-md",
    // Secondary/Tonal: Surface Container Highest
    secondary: "bg-neutral-700 hover:bg-neutral-600 text-indigo-200",
    // Ghost: Text button
    ghost: "bg-transparent hover:bg-neutral-800 text-indigo-300 hover:text-indigo-200",
    // FAB: Large, rounded (usually handled by size classes, but here's a variant)
    fab: "h-14 w-14 !p-0 rounded-[16px] bg-indigo-300 hover:bg-indigo-200 text-indigo-950 shadow-md hover:shadow-lg"
  };

  const finalClassName = variant === 'fab' 
    ? `${baseStyles.replace('h-10 px-6 rounded-full', '')} ${variants.fab} ${className}` 
    : `${baseStyles} ${variants[variant]} ${className}`;

  return (
    <button 
      className={finalClassName}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <>
          <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Processing
        </>
      ) : children}
    </button>
  );
};

import React, { useState } from 'react';
