            className="w-10 h-10 rounded-full object-cover grayscale opacity-80 hover:grayscale-0 transition-all" 
          />
          <div>
            <div className="flex items-center gap-2">
              <span className={`text-base font-medium tracking-wide ${isUser ? 'text-white' : 'text-neutral-200'}`}>
                {post.author.nickname}
              </span>
              {post.author.isAi && (
                <span className="text-[10px] px-2 py-0.5 rounded-full bg-white text-black font-bold tracking-wider">
                  BOT
                </span>
              )}
