            <span className="text-xs text-neutral-500">{formattedTime}</span>
          </div>
        </div>
        <button className="text-neutral-500 hover:text-white rounded-full p-2 hover:bg-white/10 transition-colors">
          <MoreVertical size={20} />
        </button>
      </div>

      {/* Content */}
      <div className="mb-4 pl-[56px]">
        <p className="text-base leading-relaxed tracking-wide opacity-90 text-neutral-200">
          {post.content}
        </p>
        {post.tags.length > 0 && (
          <div className="flex flex-wrap gap-2 mt-4">
            {post.tags.map(tag => (
              <span 
                key={tag} 
                className="px-3 py-1 rounded-lg bg-neutral-900 border border-neutral-800 text-xs font-medium text-neutral-400 hover:text-white hover:border-neutral-600 transition-colors cursor-pointer"
              >
                #{tag.replace('#', '')}
              </span>
            ))}
          </div>
        )}
      </div>

      {/* Actions */}
      <div className="flex items-center gap-6 pl-[56px] pt-1">
        <button 
          onClick={handleLike}
          className={`group flex items-center gap-2 text-sm font-medium transition-colors ${liked ? 'text-white' : 'text-neutral-500 hover:text-neutral-300'}`}
