          <span>{likeCount}</span>
        </button>

        <button className="group flex items-center gap-2 text-sm font-medium text-neutral-500 hover:text-white transition-colors">
          <div className="p-2 rounded-full group-hover:bg-white/10 transition-colors">
             <MessageCircle size={20} />
