      </div>

      {/* Comments Preview */}
      {post.comments.length > 0 && (
        <div className="mt-4 pt-4 pl-[56px] space-y-4 border-t border-neutral-800">
          {post.comments.map(comment => (
            <div key={comment.id} className="flex gap-3">
