                  <span className="text-[10px] text-neutral-600">• now</span>
                </div>
                <p className="text-sm text-neutral-400">{comment.content}</p>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Send, Hash, Sparkles } from 'lucide-react';
import { Button } from './Button';

interface CreatePostProps {
  onPost: (nickname: string, content: string, tags: string[]) => void;
  defaultNickname: string;
}

export const CreatePost: React.FC<CreatePostProps> = ({ onPost, defaultNickname }) => {
  const [nickname, setNickname] = useState(defaultNickname);
  const [content, setContent] = useState('');
  const [tagInput, setTagInput] = useState('');
  const [isFocused, setIsFocused] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!nickname.trim() || !content.trim()) return;

    // Parse tags from input or find in content
    const tags = tagInput.split(' ').filter(t => t.startsWith('#')).map(t => t.replace('#', ''));
    // Auto-detect tags in content if none provided
    const contentTags = content.match(/#[\w]+/g)?.map(t => t.replace('#', '')) || [];
    const finalTags = [...new Set([...tags, ...contentTags])];

    onPost(nickname, content, finalTags);
    setContent('');
    setTagInput('');
  };

  return (
    <div className={`
        bg-[#121212] rounded-[28px] p-4 mb-6 transition-all duration-300 border border-neutral-800
        ${isFocused ? 'shadow-lg shadow-white/5 border-neutral-700' : 'shadow-none'}
    `}>
      <form onSubmit={handleSubmit}>

        {/* Nickname Chip */}
        <div className="flex gap-3 mb-2">
            <div className="relative group">
                <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none">
                     <span className="text-xs text-neutral-500 font-medium">@</span>
                </div>
                <input
                    type="text"
                    value={nickname}
                    onChange={(e) => setNickname(e.target.value)}
                    placeholder="Nickname"
                    className="
                        bg-[#000000] text-neutral-200 rounded-lg pl-6 pr-3 py-1.5 text-sm font-medium
                        border border-neutral-800 focus:border-white outline-none
                        transition-colors w-32
                    "
                    required
                />
            </div>
        </div>

        {/* Text Area */}
        <div className="relative p-2">
          <textarea
            value={content}
            onChange={(e) => setContent(e.target.value)}
            onFocus={() => setIsFocused(true)}
            onBlur={() => setIsFocused(false)}
            placeholder="Share your thoughts..."
            className="w-full bg-transparent border-none text-white placeholder-neutral-600 focus:ring-0 resize-none min-h-[100px] text-base leading-relaxed p-0"
            required
          />
        </div>

        {/* Tag Input (Collapsible) */}
        <div className={`transition-all duration-300 overflow-hidden ${isFocused || content ? 'max-h-20 opacity-100 mt-2' : 'max-h-0 opacity-0'}`}>
          <div className="flex items-center gap-2 bg-[#000000] rounded-lg px-3 py-2 mx-2 border border-neutral-800">
            <Hash size={14} className="text-neutral-500" />
            <input
              type="text"
              value={tagInput}
              onChange={(e) => setTagInput(e.target.value)}
              placeholder="Tags (e.g. #random)"
              className="bg-transparent border-none text-sm text-neutral-300 placeholder-neutral-700 focus:ring-0 flex-1 p-0"
            />
          </div>
        </div>

        {/* Action Bar */}
        <div className="flex justify-between items-center mt-4 px-2">
          <div className="flex gap-1">
             <button 
                type="button" 
                className="p-2 hover:bg-white/10 rounded-full text-neutral-400 hover:text-white transition-colors" 
                title="Generate AI Suggestion"
             >
                <Sparkles size={20} />
             </button>
          </div>

          <Button 
            type="submit" 
            variant="primary"
            disabled={!content.trim() || !nickname.trim()}
          >
            <span>Post</span>
            <Send size={16} />
          </Button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Menu, Home, TrendingUp, Users } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { simulateSocialActivity } from './services/gemini';
import { Post, User, SimulationResponse } from './types';
import { LOCAL_STORAGE_KEY, INITIAL_TOPICS, MAX_POSTS_IN_MEMORY } from './constants';
import { v4 as uuidv4 } from 'uuid';

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);
  const [currentUserNickname, setCurrentUserNickname] = useState<string>('Guest');
  const [trendingTopics, setTrendingTopics] = useState<string[]>(INITIAL_TOPICS);
  const [isSimulating, setIsSimulating] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Load initial state
  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setPosts(parsed.posts || []);
        setCurrentUserNickname(parsed.nickname || 'Guest');
      } catch (e) {
        console.error("Failed to load local storage", e);
      }
    }
  }, []);

  // Save state
  useEffect(() => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      posts: posts.slice(0, MAX_POSTS_IN_MEMORY), // Keep storage clean
      nickname: currentUserNickname
    }));
  }, [posts, currentUserNickname]);

  // Helper to add post safely
  const addPost = useCallback((post: Post) => {
    setPosts(prev => [post, ...prev]);
  }, []);

  // The Engine: Handle Gemini Simulation
  const runSimulation = async (triggerPost: Post | null) => {
    setIsSimulating(true);

    // Slight delay to make it feel like "processing" network request
    if (triggerPost) await new Promise(r => setTimeout(r, 800));

    const simulationResult: SimulationResponse = await simulateSocialActivity(posts, triggerPost);

    // Apply simulation results

    // 1. Add reactions to user post (if any)
    if (simulationResult.reactionsToPost && triggerPost) {
       setPosts(currentPosts => currentPosts.map(p => {
          if (p.id === triggerPost.id) {
             const newComments = simulationResult.reactionsToPost!.comments.map(c => ({
                id: uuidv4(),
                author: { nickname: c.authorName, isAi: true, avatarSeed: c.authorName },
                content: c.content,
                timestamp: Date.now(),
                likes: Math.floor(Math.random() * 5)
             }));
             return {
                ...p,
                likes: p.likes + (simulationResult.reactionsToPost!.likesToAdd || 0),
                comments: [...newComments, ...p.comments]
             };
          }
          return p;
       }));
    }

    // 2. Add new ambient posts
    if (simulationResult.newPosts && simulationResult.newPosts.length > 0) {
        const newAiPosts: Post[] = simulationResult.newPosts.map(p => ({
            id: uuidv4(),
            author: { nickname: p.authorName, isAi: true, avatarSeed: p.authorName },
            content: p.content,
            tags: p.tags,
            timestamp: Date.now(),
            likes: Math.floor(Math.random() * 20),
            comments: []
        }));

        // Add them one by one with slight stagger for effect
        newAiPosts.forEach((p, index) => {
            setTimeout(() => {
                addPost(p);
            }, index * 2000 + 1000); // Stagger
        });
    }

    // 3. Update Trending
    if (simulationResult.trendingTopics && simulationResult.trendingTopics.length > 0) {
        setTrendingTopics(simulationResult.trendingTopics);
    }

    setIsSimulating(false);
  };

  const handleUserPost = (nickname: string, content: string, tags: string[]) => {
    setCurrentUserNickname(nickname);

    const newPost: Post = {
      id: uuidv4(),
      author: { nickname, isAi: false, avatarSeed: nickname },
      content,
      tags,
      timestamp: Date.now(),
      likes: 0,
      comments: []
    };

    addPost(newPost);

    // Trigger the simulation engine
    runSimulation(newPost);
  };

  // Ambient activity effect: If no posts for a while, generate something
  useEffect(() => {
      const interval = setInterval(() => {
          const lastPostTime = posts.length > 0 ? posts[0].timestamp : 0;
          const now = Date.now();
          // If silence for 45 seconds, poke the bear
          if (now - lastPostTime > 45000 && !isSimulating) {
              console.log("Feed silent, generating ambient noise...");
              runSimulation(null);
          }
      }, 10000); // Check every 10s

      return () => clearInterval(interval);
  }, [posts, isSimulating]);


  return (
    // M3 Surface Background
    <div className="min-h-screen bg-[#000000] text-white flex justify-center">

      {/* Layout Container */}
      <div className="flex w-full max-w-7xl h-screen">

        {/* Navigation Rail (Desktop) */}
        <nav className="hidden md:flex flex-col w-20 lg:w-72 shrink-0 border-r border-[#1F1F1F] pt-8 px-4 bg-[#000000]">
          <div className="mb-8 pl-3 flex items-center gap-3">
             <div className="w-8 h-8 rounded-lg bg-white flex items-center justify-center text-black font-bold text-xl">
               E
             </div>
             <span className="text-2xl font-bold tracking-tight hidden lg:block text-white">Echo</span>
          </div>

          <div className="space-y-2">
            <div className="flex items-center gap-4 px-4 py-4 rounded-full bg-white text-black font-bold cursor-pointer transition-transform hover:scale-[1.02]">
               <Home size={24} />
               <span className="hidden lg:block">Feed</span>
            </div>

            <div className="flex items-center gap-4 px-4 py-4 rounded-full text-neutral-500 hover:bg-[#121212] hover:text-white cursor-pointer transition-colors">
               <TrendingUp size={24} />
               <span className="hidden lg:block">Trending</span>
            </div>

            <div className="flex items-center gap-4 px-4 py-4 rounded-full text-neutral-500 hover:bg-[#121212] hover:text-white cursor-pointer transition-colors">
               <Users size={24} />
               <span className="hidden lg:block">Community</span>
            </div>
          </div>

          <div className="mt-auto mb-8 hidden lg:block">
            <div className="p-4 rounded-[24px] bg-[#0A0A0A] border border-[#1F1F1F]">
              <h3 className="text-sm font-semibold text-neutral-400 mb-4">Trending Now</h3>
              <div className="flex flex-wrap gap-2">
                {trendingTopics.map((topic, i) => (
                  <span key={i} className="text-xs px-2 py-1 rounded-md bg-[#1F1F1F] text-neutral-300 cursor-pointer hover:bg-white hover:text-black transition-colors">
                      {topic}
                  </span>
                ))}
              </div>
            </div>
          </div>
        </nav>

        {/* Main Content Area */}
        <main className="flex-1 flex flex-col h-full relative max-w-2xl mx-auto w-full">
          {/* Mobile Header */}
          <div className="md:hidden flex items-center justify-between p-4 border-b border-[#1F1F1F] bg-[#000000] sticky top-0 z-20">
             <div className="flex items-center gap-2">
               <div className="w-8 h-8 rounded-lg bg-white flex items-center justify-center text-black font-bold">E</div>
               <span className="text-xl font-medium">Echo</span>
             </div>
             <button className="p-2 text-white">
                <Menu size={24} />
             </button>
          </div>

          <div 
            ref={scrollRef}
            className="flex-1 overflow-y-auto px-4 py-6 scroll-smooth"
          >
             <div className="max-w-xl mx-auto">
                <CreatePost onPost={handleUserPost} defaultNickname={currentUserNickname} />

                <div className="space-y-2">
                    {posts.length === 0 ? (
                        <div className="text-center py-32 opacity-50">
                            <div className="text-6xl mb-4 grayscale filter contrast-200">📡</div>
                            <h2 className="text-xl font-medium mb-2">Welcome to the Void</h2>
                            <p className="text-sm text-neutral-500">Broadcast your first message to begin.</p>
                        </div>
                    ) : (
                        posts.map(post => (
                            <PostCard 
                                key={post.id} 
                                post={post} 
                                isUser={post.author.nickname === currentUserNickname && !post.author.isAi} 
                            />
                        ))
                    )}
                </div>

                <div className="h-20 flex items-center justify-center text-neutral-600 text-sm">
                    {isSimulating && (
                        <div className="flex items-center gap-2 px-4 py-2 rounded-full bg-[#121212] border border-[#222]">
                            <div className="w-1.5 h-1.5 bg-white rounded-full animate-pulse"></div>
                            <span>Processing simulation...</span>
                        </div>
                    )}
                </div>
             </div>
          </div>
        </main>

        {/* Right Sidebar - Activity (Desktop XL only) */}
        <aside className="hidden xl:flex flex-col w-80 shrink-0 border-l border-[#1F1F1F] pt-8 px-6 bg-[#000000]">
            <h3 className="text-lg font-medium mb-6 px-2 text-neutral-200">Active Nodes</h3>
            <div className="space-y-2">
                {[1,2,3,4,5].map((_, i) => (
                    <div key={i} className="flex items-center gap-3 p-3 rounded-full hover:bg-[#121212] cursor-pointer transition-colors group">
                        <div className="relative">
                           <img src={`https://api.dicebear.com/7.x/notionists/svg?seed=user${i}&backgroundColor=e4e2e2`} alt="User" className="w-10 h-10 rounded-full bg-neutral-800 grayscale opacity-70 group-hover:grayscale-0 group-hover:opacity-100 transition-all" />
                           <div className="absolute bottom-0 right-0 w-3 h-3 bg-white border-2 border-black rounded-full"></div>
                        </div>
                        <div>
                            <div className="text-sm font-medium text-neutral-400 group-hover:text-white transition-colors">User_0{i + 142}</div>
                            <div className="text-xs text-neutral-600">Connected</div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="mt-8 p-4 bg-[#0A0A0A] border border-[#1F1F1F] rounded-[24px] text-neutral-400 text-sm leading-relaxed">
               <p><strong className="text-white">Experiment Status:</strong> Live</p>
               <p className="opacity-70 mt-1">This is a decentralized simulation. Messages are persisted locally. The network is hallucinating.</p>
            </div>
        </aside>

      </div>
    </div>
  );
}

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost' | 'fab';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {
  // M3 Base: 40px height, rounded-full, font-medium tracking-wide
  const baseStyles = "h-10 px-6 rounded-full font-medium text-sm tracking-wide transition-all duration-200 flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed active:scale-[0.98]";

  const variants = {
    // Primary: 
    // Light Mode: Black bg, White text 
    // Dark Mode: White bg, Black text
    primary: "bg-black text-white hover:bg-neutral-800 shadow-sm dark:bg-white dark:text-black dark:hover:bg-neutral-200",

    // Secondary: 
    // Light Mode: Grey-100 bg, Black text
    // Dark Mode: Grey-800 bg, White text
    secondary: "bg-neutral-100 text-black border border-neutral-200 hover:bg-neutral-200 dark:bg-neutral-800 dark:text-white dark:border-neutral-700 dark:hover:bg-neutral-700",

    // Ghost: 
    // Adaptive text color
    ghost: "bg-transparent text-neutral-600 hover:bg-neutral-100 hover:text-black dark:text-neutral-400 dark:hover:bg-neutral-900 dark:hover:text-white",

    // FAB: 
    // Inverted high contrast
    fab: "h-14 w-14 !p-0 rounded-[16px] shadow-md bg-black text-white hover:bg-neutral-800 dark:bg-white dark:text-black dark:hover:bg-neutral-200"
  };

  const finalClassName = variant === 'fab' 
    ? `${baseStyles.replace('h-10 px-6 rounded-full', '')} ${variants.fab} ${className}` 
    : `${baseStyles} ${variants[variant]} ${className}`;

  return (
    <button 
      className={finalClassName}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <>
          <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Processing
        </>
      ) : children}
    </button>
  );
};

import React, { useState } from 'react';
import { Heart, MessageCircle, Share2, MoreVertical } from 'lucide-react';
import { Post } from '../types';
import { DEFAULT_AVATAR_URL } from '../constants';

interface PostCardProps {
  post: Post;
  isUser: boolean;
}

export const PostCard: React.FC<PostCardProps> = ({ post, isUser }) => {
  const [liked, setLiked] = useState(false);
  const [likeCount, setLikeCount] = useState(post.likes);

  const handleLike = () => {
    if (liked) {
      setLikeCount(prev => prev - 1);
    } else {
      setLikeCount(prev => prev + 1);
    }
    setLiked(!liked);
  };

  const formattedTime = new Intl.DateTimeFormat('en-US', {
    hour: 'numeric',
    minute: 'numeric',
  }).format(new Date(post.timestamp));

  return (
    <div className={`
      relative p-5 mb-4 transition-all duration-300
      rounded-[24px] border
      ${isUser 
        ? 'bg-neutral-100 border-neutral-200 text-black dark:bg-[#1A1A1A] dark:border-neutral-700 dark:text-white' 
        : 'bg-white border-neutral-200 text-neutral-800 dark:bg-[#0A0A0A] dark:border-[#1F1F1F] dark:text-neutral-300' 
      }
    `}>
      {/* Header */}
      <div className="flex items-start justify-between mb-4">
        <div className="flex items-center gap-4">
          <img 
            src={DEFAULT_AVATAR_URL(post.author.avatarSeed)} 
            alt={post.author.nickname}
            className="w-10 h-10 rounded-full object-cover grayscale opacity-80 hover:grayscale-0 transition-all border border-neutral-200 dark:border-neutral-800" 
          />
          <div>
            <div className="flex items-center gap-2">
              <span className={`text-base font-medium tracking-wide ${isUser ? 'text-black dark:text-white' : 'text-neutral-900 dark:text-neutral-200'}`}>
                {post.author.nickname}
              </span>
              {post.author.isAi && (
                <span className="text-[10px] px-2 py-0.5 rounded-full bg-black text-white dark:bg-white dark:text-black font-bold tracking-wider">
                  BOT
                </span>
              )}
            </div>
            <span className="text-xs text-neutral-500 dark:text-neutral-500">{formattedTime}</span>
          </div>
        </div>
        <button className="text-neutral-400 hover:text-black dark:text-neutral-500 dark:hover:text-white rounded-full p-2 hover:bg-black/5 dark:hover:bg-white/10 transition-colors">
          <MoreVertical size={20} />
        </button>
      </div>

      {/* Content */}
      <div className="mb-4 pl-[56px]">
        <p className="text-base leading-relaxed tracking-wide opacity-90 text-neutral-800 dark:text-neutral-200">
          {post.content}
        </p>
        {post.tags.length > 0 && (
          <div className="flex flex-wrap gap-2 mt-4">
            {post.tags.map(tag => (
              <span 
                key={tag} 
                className="px-3 py-1 rounded-lg text-xs font-medium transition-colors cursor-pointer
                           bg-neutral-100 border border-neutral-200 text-neutral-600 hover:bg-neutral-200 hover:text-black
                           dark:bg-neutral-900 dark:border-neutral-800 dark:text-neutral-400 dark:hover:text-white dark:hover:border-neutral-600"
              >
                #{tag.replace('#', '')}
              </span>
            ))}
          </div>
        )}
      </div>

      {/* Actions */}
      <div className="flex items-center gap-6 pl-[56px] pt-1">
        <button 
          onClick={handleLike}
          className={`group flex items-center gap-2 text-sm font-medium transition-colors 
            ${liked 
              ? 'text-black dark:text-white' 
              : 'text-neutral-500 hover:text-black dark:text-neutral-500 dark:hover:text-neutral-300'
            }`}
        >
          <div className={`p-2 rounded-full group-hover:bg-black/5 dark:group-hover:bg-white/10 transition-colors`}>
             <Heart size={20} fill={liked ? "currentColor" : "none"} className={liked ? "scale-110" : ""} />
          </div>
          <span>{likeCount}</span>
        </button>

        <button className="group flex items-center gap-2 text-sm font-medium text-neutral-500 hover:text-black dark:text-neutral-500 dark:hover:text-white transition-colors">
          <div className="p-2 rounded-full group-hover:bg-black/5 dark:group-hover:bg-white/10 transition-colors">
             <MessageCircle size={20} />
          </div>
          <span>{post.comments.length}</span>
        </button>

        <button className="group flex items-center gap-2 text-sm font-medium text-neutral-500 hover:text-black dark:text-neutral-500 dark:hover:text-white transition-colors">
           <div className="p-2 rounded-full group-hover:bg-black/5 dark:group-hover:bg-white/10 transition-colors">
              <Share2 size={20} />
           </div>
        </button>
      </div>

      {/* Comments Preview */}
      {post.comments.length > 0 && (
        <div className="mt-4 pt-4 pl-[56px] space-y-4 border-t border-neutral-100 dark:border-neutral-800">
          {post.comments.map(comment => (
            <div key={comment.id} className="flex gap-3">
