                  <span className="text-sm font-medium text-neutral-900 dark:text-neutral-300">{comment.author.nickname}</span>
                  <span className="text-[10px] text-neutral-500 dark:text-neutral-600">• now</span>
                </div>
                <p className="text-sm text-neutral-600 dark:text-neutral-400">{comment.content}</p>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Send, Hash, Sparkles } from 'lucide-react';
import { Button } from './Button';

interface CreatePostProps {
  onPost: (nickname: string, content: string, tags: string[]) => void;
  defaultNickname: string;
}

export const CreatePost: React.FC<CreatePostProps> = ({ onPost, defaultNickname }) => {
  const [nickname, setNickname] = useState(defaultNickname);
  const [content, setContent] = useState('');
  const [tagInput, setTagInput] = useState('');
  const [isFocused, setIsFocused] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!nickname.trim() || !content.trim()) return;

    // Parse tags from input or find in content
    const tags = tagInput.split(' ').filter(t => t.startsWith('#')).map(t => t.replace('#', ''));
    // Auto-detect tags in content if none provided
    const contentTags = content.match(/#[\w]+/g)?.map(t => t.replace('#', '')) || [];
    const finalTags = [...new Set([...tags, ...contentTags])];

    onPost(nickname, content, finalTags);
    setContent('');
    setTagInput('');
  };

  return (
    <div className={`
        rounded-[28px] p-4 mb-6 transition-all duration-300 border
        bg-white border-neutral-200 dark:bg-[#121212] dark:border-neutral-800
        ${isFocused ? 'shadow-lg shadow-black/5 dark:shadow-white/5 border-neutral-300 dark:border-neutral-700' : 'shadow-none'}
    `}>
      <form onSubmit={handleSubmit}>

        {/* Nickname Chip */}
        <div className="flex gap-3 mb-2">
            <div className="relative group">
                <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none">
                     <span className="text-xs text-neutral-500 font-medium">@</span>
                </div>
                <input
                    type="text"
                    value={nickname}
                    onChange={(e) => setNickname(e.target.value)}
                    placeholder="Nickname"
                    className="
                        rounded-lg pl-6 pr-3 py-1.5 text-sm font-medium outline-none transition-colors w-32
                        bg-neutral-50 text-neutral-900 border border-neutral-200 focus:border-black
                        dark:bg-[#000000] dark:text-neutral-200 dark:border-neutral-800 dark:focus:border-white
                    "
                    required
                />
            </div>
        </div>

        {/* Text Area */}
        <div className="relative p-2">
          <textarea
            value={content}
            onChange={(e) => setContent(e.target.value)}
            onFocus={() => setIsFocused(true)}
            onBlur={() => setIsFocused(false)}
            placeholder="Share your thoughts..."
            className="w-full bg-transparent border-none focus:ring-0 resize-none min-h-[100px] text-base leading-relaxed p-0
                       text-neutral-900 placeholder-neutral-400
                       dark:text-white dark:placeholder-neutral-600"
            required
          />
        </div>

        {/* Tag Input (Collapsible) */}
        <div className={`transition-all duration-300 overflow-hidden ${isFocused || content ? 'max-h-20 opacity-100 mt-2' : 'max-h-0 opacity-0'}`}>
          <div className="flex items-center gap-2 rounded-lg px-3 py-2 mx-2 border
                          bg-neutral-50 border-neutral-200
                          dark:bg-[#000000] dark:border-neutral-800">
            <Hash size={14} className="text-neutral-400 dark:text-neutral-500" />
            <input
              type="text"
              value={tagInput}
              onChange={(e) => setTagInput(e.target.value)}
              placeholder="Tags (e.g. #random)"
              className="bg-transparent border-none text-sm focus:ring-0 flex-1 p-0
                         text-neutral-700 placeholder-neutral-400
                         dark:text-neutral-300 dark:placeholder-neutral-700"
            />
          </div>
        </div>

        {/* Action Bar */}
        <div className="flex justify-between items-center mt-4 px-2">
          <div className="flex gap-1">
             <button 
                type="button" 
                className="p-2 rounded-full transition-colors
                           text-neutral-500 hover:bg-neutral-100 hover:text-black
                           dark:text-neutral-400 dark:hover:bg-white/10 dark:hover:text-white" 
                title="Generate AI Suggestion"
             >
                <Sparkles size={20} />
             </button>
          </div>

          <Button 
            type="submit" 
            variant="primary"
            disabled={!content.trim() || !nickname.trim()}
          >
            <span>Post</span>
            <Send size={16} />
          </Button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Menu, Home, TrendingUp, Users, Sun, Moon } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { simulateSocialActivity } from './services/gemini';
import { Post, User, SimulationResponse } from './types';
import { LOCAL_STORAGE_KEY, INITIAL_TOPICS, MAX_POSTS_IN_MEMORY } from './constants';
import { v4 as uuidv4 } from 'uuid';

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);
  const [currentUserNickname, setCurrentUserNickname] = useState<string>('Guest');
  const [trendingTopics, setTrendingTopics] = useState<string[]>(INITIAL_TOPICS);
  const [isSimulating, setIsSimulating] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('echo_theme');
      if (saved === 'light' || saved === 'dark') return saved;
      return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    }
    return 'dark'; // Default fallback
  });

  const scrollRef = useRef<HTMLDivElement>(null);

  // Apply Theme
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('echo_theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'dark' ? 'light' : 'dark');
  };

  // Load initial state
  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setPosts(parsed.posts || []);
        setCurrentUserNickname(parsed.nickname || 'Guest');
      } catch (e) {
        console.error("Failed to load local storage", e);
      }
    }
  }, []);

  // Save state
  useEffect(() => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      posts: posts.slice(0, MAX_POSTS_IN_MEMORY), // Keep storage clean
      nickname: currentUserNickname
    }));
  }, [posts, currentUserNickname]);

  // Helper to add post safely
  const addPost = useCallback((post: Post) => {
    setPosts(prev => [post, ...prev]);
  }, []);

  // The Engine: Handle Gemini Simulation
  const runSimulation = async (triggerPost: Post | null) => {
    setIsSimulating(true);

    // Slight delay to make it feel like "processing" network request
    if (triggerPost) await new Promise(r => setTimeout(r, 800));

    const simulationResult: SimulationResponse = await simulateSocialActivity(posts, triggerPost);

    // Apply simulation results

    // 1. Add reactions to user post (if any)
    if (simulationResult.reactionsToPost && triggerPost) {
       setPosts(currentPosts => currentPosts.map(p => {
          if (p.id === triggerPost.id) {
             const newComments = simulationResult.reactionsToPost!.comments.map(c => ({
                id: uuidv4(),
                author: { nickname: c.authorName, isAi: true, avatarSeed: c.authorName },
                content: c.content,
                timestamp: Date.now(),
                likes: Math.floor(Math.random() * 5)
             }));
             return {
                ...p,
                likes: p.likes + (simulationResult.reactionsToPost!.likesToAdd || 0),
                comments: [...newComments, ...p.comments]
             };
          }
          return p;
       }));
    }

    // 2. Add new ambient posts
    if (simulationResult.newPosts && simulationResult.newPosts.length > 0) {
        const newAiPosts: Post[] = simulationResult.newPosts.map(p => ({
            id: uuidv4(),
            author: { nickname: p.authorName, isAi: true, avatarSeed: p.authorName },
            content: p.content,
            tags: p.tags,
            timestamp: Date.now(),
            likes: Math.floor(Math.random() * 20),
            comments: []
        }));

        // Add them one by one with slight stagger for effect
        newAiPosts.forEach((p, index) => {
            setTimeout(() => {
                addPost(p);
            }, index * 2000 + 1000); // Stagger
        });
    }

    // 3. Update Trending
    if (simulationResult.trendingTopics && simulationResult.trendingTopics.length > 0) {
        setTrendingTopics(simulationResult.trendingTopics);
    }

    setIsSimulating(false);
  };

  const handleUserPost = (nickname: string, content: string, tags: string[]) => {
    setCurrentUserNickname(nickname);

    const newPost: Post = {
      id: uuidv4(),
      author: { nickname, isAi: false, avatarSeed: nickname },
      content,
      tags,
      timestamp: Date.now(),
      likes: 0,
      comments: []
    };

    addPost(newPost);

    // Trigger the simulation engine
    runSimulation(newPost);
  };

  // Ambient activity effect: If no posts for a while, generate something
  useEffect(() => {
      const interval = setInterval(() => {
          const lastPostTime = posts.length > 0 ? posts[0].timestamp : 0;
          const now = Date.now();
          // If silence for 45 seconds, poke the bear
          if (now - lastPostTime > 45000 && !isSimulating) {
              console.log("Feed silent, generating ambient noise...");
              runSimulation(null);
          }
      }, 10000); // Check every 10s

      return () => clearInterval(interval);
  }, [posts, isSimulating]);


  return (
    // Theme-aware container
    <div className="min-h-screen flex justify-center transition-colors duration-300
                    bg-[#F5F5F5] text-neutral-900
                    dark:bg-[#000000] dark:text-white">

      {/* Layout Container */}
      <div className="flex w-full max-w-7xl h-screen">

        {/* Navigation Rail (Desktop) */}
        <nav className="hidden md:flex flex-col w-20 lg:w-72 shrink-0 pt-8 px-4 transition-colors border-r
                        bg-white border-neutral-200
                        dark:bg-[#000000] dark:border-[#1F1F1F]">

          <div className="mb-8 pl-3 flex items-center justify-between">
             <div className="flex items-center gap-3">
               <div className="w-8 h-8 rounded-lg flex items-center justify-center font-bold text-xl
                               bg-black text-white dark:bg-white dark:text-black">
                 E
               </div>
               <span className="text-2xl font-bold tracking-tight hidden lg:block">Echo</span>
             </div>
          </div>

          <div className="space-y-2">
            <div className="flex items-center gap-4 px-4 py-4 rounded-full font-bold cursor-pointer transition-transform hover:scale-[1.02]
                            bg-black text-white
                            dark:bg-white dark:text-black">
               <Home size={24} />
               <span className="hidden lg:block">Feed</span>
            </div>

            <div className="flex items-center gap-4 px-4 py-4 rounded-full cursor-pointer transition-colors
                            text-neutral-500 hover:bg-neutral-100 hover:text-black
                            dark:text-neutral-500 dark:hover:bg-[#121212] dark:hover:text-white">
               <TrendingUp size={24} />
               <span className="hidden lg:block">Trending</span>
            </div>

            <div className="flex items-center gap-4 px-4 py-4 rounded-full cursor-pointer transition-colors
                            text-neutral-500 hover:bg-neutral-100 hover:text-black
                            dark:text-neutral-500 dark:hover:bg-[#121212] dark:hover:text-white">
               <Users size={24} />
               <span className="hidden lg:block">Community</span>
            </div>

            <button onClick={toggleTheme}
               className="flex items-center gap-4 px-4 py-4 rounded-full cursor-pointer transition-colors w-full text-left
                          text-neutral-500 hover:bg-neutral-100 hover:text-black
                          dark:text-neutral-500 dark:hover:bg-[#121212] dark:hover:text-white">
               {theme === 'dark' ? <Sun size={24} /> : <Moon size={24} />}
               <span className="hidden lg:block">{theme === 'dark' ? 'Light Mode' : 'Dark Mode'}</span>
            </button>
          </div>

          <div className="mt-auto mb-8 hidden lg:block">
            <div className="p-4 rounded-[24px] border
                            bg-neutral-50 border-neutral-200
                            dark:bg-[#0A0A0A] dark:border-[#1F1F1F]">
              <h3 className="text-sm font-semibold mb-4 text-neutral-500 dark:text-neutral-400">Trending Now</h3>
              <div className="flex flex-wrap gap-2">
                {trendingTopics.map((topic, i) => (
                  <span key={i} className="text-xs px-2 py-1 rounded-md cursor-pointer transition-colors
                                           bg-white text-neutral-700 hover:bg-black hover:text-white
                                           dark:bg-[#1F1F1F] dark:text-neutral-300 dark:hover:bg-white dark:hover:text-black">
                      {topic}
                  </span>
                ))}
              </div>
            </div>
          </div>
        </nav>

        {/* Main Content Area */}
        <main className="flex-1 flex flex-col h-full relative max-w-2xl mx-auto w-full">
          {/* Mobile Header */}
          <div className="md:hidden flex items-center justify-between p-4 border-b sticky top-0 z-20 transition-colors
                          bg-white border-neutral-200 text-black
                          dark:bg-[#000000] dark:border-[#1F1F1F] dark:text-white">
             <div className="flex items-center gap-2">
               <div className="w-8 h-8 rounded-lg flex items-center justify-center font-bold
                               bg-black text-white dark:bg-white dark:text-black">E</div>
               <span className="text-xl font-medium">Echo</span>
             </div>
             <div className="flex gap-2">
                <button onClick={toggleTheme} className="p-2">
                  {theme === 'dark' ? <Sun size={24} /> : <Moon size={24} />}
                </button>
                <button className="p-2">
                    <Menu size={24} />
                </button>
             </div>
          </div>

          <div 
            ref={scrollRef}
            className="flex-1 overflow-y-auto px-4 py-6 scroll-smooth"
          >
             <div className="max-w-xl mx-auto">
                <CreatePost onPost={handleUserPost} defaultNickname={currentUserNickname} />

                <div className="space-y-2">
                    {posts.length === 0 ? (
                        <div className="text-center py-32 opacity-50">
                            <div className="text-6xl mb-4 grayscale filter contrast-200">📡</div>
                            <h2 className="text-xl font-medium mb-2">Welcome to the Void</h2>
                            <p className="text-sm text-neutral-500">Broadcast your first message to begin.</p>
                        </div>
                    ) : (
                        posts.map(post => (
                            <PostCard 
                                key={post.id} 
                                post={post} 
                                isUser={post.author.nickname === currentUserNickname && !post.author.isAi} 
                            />
                        ))
                    )}
                </div>

                <div className="h-20 flex items-center justify-center text-sm
                                text-neutral-500 dark:text-neutral-600">
                    {isSimulating && (
                        <div className="flex items-center gap-2 px-4 py-2 rounded-full border
                                        bg-white border-neutral-200
                                        dark:bg-[#121212] dark:border-[#222]">
                            <div className="w-1.5 h-1.5 rounded-full animate-pulse
                                            bg-black dark:bg-white"></div>
                            <span>Processing simulation...</span>
                        </div>
                    )}
                </div>
             </div>
          </div>
        </main>

        {/* Right Sidebar - Activity (Desktop XL only) */}
        <aside className="hidden xl:flex flex-col w-80 shrink-0 border-l pt-8 px-6 transition-colors
                          bg-white border-neutral-200
                          dark:bg-[#000000] dark:border-[#1F1F1F]">
            <h3 className="text-lg font-medium mb-6 px-2 text-neutral-800 dark:text-neutral-200">Active Nodes</h3>
            <div className="space-y-2">
                {[1,2,3,4,5].map((_, i) => (
                    <div key={i} className="flex items-center gap-3 p-3 rounded-full cursor-pointer transition-colors group
                                            hover:bg-neutral-100 dark:hover:bg-[#121212]">
                        <div className="relative">
                           <img src={`https://api.dicebear.com/7.x/notionists/svg?seed=user${i}&backgroundColor=e4e2e2`} alt="User" 
                                className="w-10 h-10 rounded-full grayscale opacity-70 group-hover:grayscale-0 group-hover:opacity-100 transition-all
                                           bg-neutral-200 dark:bg-neutral-800" />
                           <div className="absolute bottom-0 right-0 w-3 h-3 rounded-full border-2
                                           bg-black border-white
                                           dark:bg-white dark:border-black"></div>
                        </div>
                        <div>
                            <div className="text-sm font-medium transition-colors
                                            text-neutral-600 group-hover:text-black
                                            dark:text-neutral-400 dark:group-hover:text-white">User_0{i + 142}</div>
                            <div className="text-xs text-neutral-500 dark:text-neutral-600">Connected</div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="mt-8 p-4 rounded-[24px] border text-sm leading-relaxed
                            bg-neutral-50 border-neutral-200 text-neutral-600
                            dark:bg-[#0A0A0A] dark:border-[#1F1F1F] dark:text-neutral-400">
               <p><strong className="text-black dark:text-white">Experiment Status:</strong> Live</p>
               <p className="opacity-70 mt-1">This is a decentralized simulation. Messages are persisted locally. The network is hallucinating.</p>
            </div>
        </aside>

      </div>
    </div>
  );
}

