export interface User {
  nickname: string;
  avatarSeed: string; // For generating consistent avatars
  isAi: boolean;
}

export interface Comment {
  id: string;
  author: User;
  content: string;
  timestamp: number;
  likes: number;
}

export interface Post {
  id: string;
  author: User;
  content: string;
  tags: string[];
  timestamp: number;
  likes: number;
  comments: Comment[];
}

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Menu, Home, TrendingUp, Users, Sun, Moon, Database } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { Post, User } from './types';
import { LOCAL_STORAGE_KEY, INITIAL_TOPICS, MAX_POSTS_IN_MEMORY } from './constants';
import { v4 as uuidv4 } from 'uuid';

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);
  const [currentUserNickname, setCurrentUserNickname] = useState<string>('Guest');

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('echo_theme');
      if (saved === 'light' || saved === 'dark') return saved;
      return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    }
    return 'dark'; // Default fallback
  });

  const scrollRef = useRef<HTMLDivElement>(null);

  // Apply Theme
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('echo_theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'dark' ? 'light' : 'dark');
  };

  // Load initial state
  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setPosts(parsed.posts || []);
        setCurrentUserNickname(parsed.nickname || 'Guest');
      } catch (e) {
        console.error("Failed to load local storage", e);
      }
    }
  }, []);

  // Save state
  useEffect(() => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      posts: posts.slice(0, MAX_POSTS_IN_MEMORY), // Keep storage clean
      nickname: currentUserNickname
    }));
  }, [posts, currentUserNickname]);

  // Calculate real stats from local data
  const activeUsers = useMemo(() => {
    const uniqueUsers = new Map();
    posts.forEach(post => {
      if (!uniqueUsers.has(post.author.nickname)) {
        uniqueUsers.set(post.author.nickname, post.author.avatarSeed);
      }
    });
    return Array.from(uniqueUsers.entries()).map(([nickname, seed]) => ({ nickname, seed }));
  }, [posts]);

  const trendingTopics = useMemo(() => {
    const counts: Record<string, number> = {};
    posts.forEach(post => {
      post.tags.forEach(tag => {
        counts[tag] = (counts[tag] || 0) + 1;
      });
    });

    const sorted = Object.entries(counts).sort((a, b) => b[1] - a[1]);
    return sorted.length > 0 ? sorted.slice(0, 5).map(t => '#' + t[0]) : INITIAL_TOPICS;
  }, [posts]);

  // Handle new posts
  const handleUserPost = (nickname: string, content: string, tags: string[]) => {
    setCurrentUserNickname(nickname);

    const newPost: Post = {
      id: uuidv4(),
      author: { nickname, isAi: false, avatarSeed: nickname },
      content,
      tags,
      timestamp: Date.now(),
      likes: 0,
      comments: []
    };

    setPosts(prev => [newPost, ...prev]);
  };

  const handleClearData = () => {
    if(window.confirm("Are you sure you want to wipe all local data?")) {
        setPosts([]);
        localStorage.removeItem(LOCAL_STORAGE_KEY);
    }
  }

  return (
    // Theme-aware container
    <div className="min-h-screen flex justify-center transition-colors duration-300
                    bg-[#F5F5F5] text-neutral-900
                    dark:bg-[#000000] dark:text-white">

      {/* Layout Container */}
      <div className="flex w-full max-w-7xl h-screen">

        {/* Navigation Rail (Desktop) */}
        <nav className="hidden md:flex flex-col w-20 lg:w-72 shrink-0 pt-8 px-4 transition-colors border-r
                        bg-white border-neutral-200
                        dark:bg-[#000000] dark:border-[#1F1F1F]">

          <div className="mb-8 flex items-center justify-center lg:justify-start lg:pl-4">
             <span className="text-2xl font-bold tracking-tight">Echo</span>
          </div>

          <div className="space-y-2">
            <div className="flex items-center gap-4 px-4 py-4 rounded-full font-bold cursor-pointer transition-transform hover:scale-[1.02]
                            bg-black text-white
                            dark:bg-white dark:text-black">
               <Home size={24} />
               <span className="hidden lg:block">Feed</span>
            </div>

            <div className="flex items-center gap-4 px-4 py-4 rounded-full cursor-pointer transition-colors
                            text-neutral-500 hover:bg-neutral-100 hover:text-black
                            dark:text-neutral-500 dark:hover:bg-[#121212] dark:hover:text-white">
               <TrendingUp size={24} />
               <span className="hidden lg:block">Trending</span>
            </div>

            <button onClick={toggleTheme}
               className="flex items-center gap-4 px-4 py-4 rounded-full cursor-pointer transition-colors w-full text-left
                          text-neutral-500 hover:bg-neutral-100 hover:text-black
                          dark:text-neutral-500 dark:hover:bg-[#121212] dark:hover:text-white">
               {theme === 'dark' ? <Sun size={24} /> : <Moon size={24} />}
               <span className="hidden lg:block">{theme === 'dark' ? 'Light Mode' : 'Dark Mode'}</span>
            </button>
          </div>

          <div className="mt-auto mb-8 hidden lg:block">
            <div className="p-4 rounded-[24px] border
                            bg-neutral-50 border-neutral-200
                            dark:bg-[#0A0A0A] dark:border-[#1F1F1F]">
              <h3 className="text-sm font-semibold mb-4 text-neutral-500 dark:text-neutral-400">Trending Now</h3>
              <div className="flex flex-wrap gap-2">
                {trendingTopics.map((topic, i) => (
                  <span key={i} className="text-xs px-2 py-1 rounded-md cursor-pointer transition-colors
                                           bg-white text-neutral-700 hover:bg-black hover:text-white
                                           dark:bg-[#1F1F1F] dark:text-neutral-300 dark:hover:bg-white dark:hover:text-black">
                      {topic}
                  </span>
                ))}
              </div>
            </div>
          </div>
        </nav>

        {/* Main Content Area */}
        <main className="flex-1 flex flex-col h-full relative max-w-2xl mx-auto w-full">
          {/* Mobile Header */}
          <div className="md:hidden flex items-center justify-between p-4 border-b sticky top-0 z-20 transition-colors
                          bg-white border-neutral-200 text-black
                          dark:bg-[#000000] dark:border-[#1F1F1F] dark:text-white">
             <div className="flex items-center gap-2">
               <span className="text-xl font-bold tracking-tight">Echo</span>
             </div>
             <div className="flex gap-2">
                <button onClick={toggleTheme} className="p-2">
                  {theme === 'dark' ? <Sun size={24} /> : <Moon size={24} />}
                </button>
                <button className="p-2">
                    <Menu size={24} />
                </button>
             </div>
          </div>

          <div 
            ref={scrollRef}
            className="flex-1 overflow-y-auto px-4 py-6 scroll-smooth"
          >
             <div className="max-w-xl mx-auto">
                <CreatePost onPost={handleUserPost} defaultNickname={currentUserNickname} />

                <div className="space-y-2">
                    {posts.length === 0 ? (
                        <div className="text-center py-32 opacity-50">
                            <div className="text-6xl mb-4 grayscale filter contrast-200">📝</div>
                            <h2 className="text-xl font-medium mb-2">No Posts Yet</h2>
                            <p className="text-sm text-neutral-500">Posts are stored locally in your browser.</p>
                        </div>
                    ) : (
                        posts.map(post => (
                            <PostCard 
                                key={post.id} 
                                post={post} 
                                isUser={post.author.nickname === currentUserNickname} 
                            />
                        ))
                    )}
                </div>

                <div className="h-20 flex items-center justify-center">
                    <p className="text-xs text-neutral-400 dark:text-neutral-600">
                        {posts.length} post{posts.length !== 1 ? 's' : ''} stored locally
                    </p>
                </div>
             </div>
          </div>
        </main>

        {/* Right Sidebar - Activity (Desktop XL only) */}
        <aside className="hidden xl:flex flex-col w-80 shrink-0 border-l pt-8 px-6 transition-colors
                          bg-white border-neutral-200
                          dark:bg-[#000000] dark:border-[#1F1F1F]">

            {/* Active Users Section */}
            <div className="mb-6">
                <h3 className="text-lg font-medium mb-4 px-2 text-neutral-800 dark:text-neutral-200">Contributors</h3>
                <div className="space-y-2">
                    {activeUsers.length === 0 ? (
                        <p className="px-2 text-sm text-neutral-500">No users yet.</p>
                    ) : (
                        activeUsers.slice(0, 8).map((user, i) => (
                            <div key={i} className="flex items-center gap-3 p-3 rounded-full cursor-pointer transition-colors group
                                                    hover:bg-neutral-100 dark:hover:bg-[#121212]">
                                <img src={`https://api.dicebear.com/7.x/notionists/svg?seed=${user.seed}&backgroundColor=e4e2e2`} alt="User" 
                                        className="w-10 h-10 rounded-full grayscale opacity-70 group-hover:grayscale-0 group-hover:opacity-100 transition-all
                                                bg-neutral-200 dark:bg-neutral-800" />
                                <div>
                                    <div className="text-sm font-medium transition-colors
                                                    text-neutral-600 group-hover:text-black
                                                    dark:text-neutral-400 dark:group-hover:text-white">@{user.nickname}</div>
                                </div>
                            </div>
                        ))
                    )}
                </div>
            </div>

            <div className="mt-auto mb-8 p-4 rounded-[24px] border text-sm leading-relaxed
                            bg-neutral-50 border-neutral-200 text-neutral-600
                            dark:bg-[#0A0A0A] dark:border-[#1F1F1F] dark:text-neutral-400">
               <div className="flex items-center gap-2 mb-2 font-semibold text-black dark:text-white">
                   <Database size={16} />
                   <span>Storage Status</span>
               </div>
               <p className="opacity-70 mb-3">
                   Data is stored in your browser's Local Storage. It will persist until you clear your cache.
               </p>
               <button 
                  onClick={handleClearData}
                  className="text-xs font-medium underline hover:text-red-500 transition-colors"
               >
                   Wipe Data
               </button>
            </div>
        </aside>

      </div>
    </div>
  );
}

