import { createClient, SupabaseClient } from '@supabase/supabase-js';
import { Post } from '../types';

let supabase: SupabaseClient | null = null;

export const MAX_POSTS_LIMIT = 100; // Hard limit to keep DB free and fast

export const initSupabase = (url: string, key: string) => {
  try {
    supabase = createClient(url, key);
    localStorage.setItem('echo_supabase_config', JSON.stringify({ url, key }));
    return true;
  } catch (e) {
    console.error("Invalid Supabase Config", e);
    return false;
  }
};

export const getSupabase = () => {
  if (supabase) return supabase;

  // Try to load from storage
  const saved = localStorage.getItem('echo_supabase_config');
  if (saved) {
    const { url, key } = JSON.parse(saved);
    if (url && key) {
      return initSupabase(url, key) ? supabase : null;
    }
  }
  return null;
};

export const disconnectSupabase = () => {
  supabase = null;
  localStorage.removeItem('echo_supabase_config');
};

// Map DB row to App Post type
const mapRowToPost = (row: any): Post => ({
  id: row.id,
  author: {
    nickname: row.nickname,
    avatarSeed: row.avatar_seed,
    isAi: false
  },
  content: row.content,
  tags: row.tags || [],
  timestamp: new Date(row.created_at).getTime(),
  likes: row.likes,
  comments: [] // Comments would require another table, keeping simple for now
});

export const fetchPosts = async (): Promise<Post[]> => {
  const client = getSupabase();
  if (!client) throw new Error("Not connected");

  const { data, error } = await client
    .from('posts')
    .select('*')
    .order('created_at', { ascending: false })
    .limit(MAX_POSTS_LIMIT);

  if (error) throw error;
  return (data || []).map(mapRowToPost);
};

export const createPost = async (nickname: string, content: string, tags: string[]): Promise<Post | null> => {
  const client = getSupabase();
  if (!client) throw new Error("Not connected");

  // 1. Insert new post
  const { data, error } = await client
    .from('posts')
    .insert([{
      nickname,
      content,
      tags,
      avatar_seed: nickname,
      likes: 0
    }])
    .select()
    .single();

  if (error) throw error;

  // 2. Auto-Cleanup: Delete old posts to save space (Client-side trigger)
  // This is a "hack" to avoid backend functions. We just check count and delete oldest.
  // Note: This requires RLS to allow Deletes or be disabled.
  cleanUpOldPosts(client);

  return mapRowToPost(data);
};

const cleanUpOldPosts = async (client: SupabaseClient) => {
  try {
    // Check count
    const { count } = await client.from('posts').select('*', { count: 'exact', head: true });

    if (count !== null && count > MAX_POSTS_LIMIT) {
      // Find oldest posts
      const excess = count - MAX_POSTS_LIMIT;

      // We need to fetch IDs of oldest posts to delete them
      const { data: oldPosts } = await client
        .from('posts')
        .select('id')
        .order('created_at', { ascending: true })
        .limit(excess + 5); // Delete a few extra to be safe

      if (oldPosts && oldPosts.length > 0) {
        const ids = oldPosts.map(p => p.id);
        await client.from('posts').delete().in('id', ids);
      }
    }
  } catch (e) {
    console.warn("Cleanup failed (likely permission issue, harmless)", e);
  }
};

export const toggleLike = async (postId: string, increment: boolean) => {
  const client = getSupabase();
  if (!client) return;

  // RPC is better, but simple update works for low traffic
  // Note: This is prone to race conditions without RPC, but fine for prototype
  const { data } = await client.from('posts').select('likes').eq('id', postId).single();
  if (data) {
    const newLikes = Math.max(0, data.likes + (increment ? 1 : -1));
    await client.from('posts').update({ likes: newLikes }).eq('id', postId);
  }
};

export const subscribeToPosts = (callback: (payload: any) => void) => {
  const client = getSupabase();
  if (!client) return null;

  return client
    .channel('public:posts')
    .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'posts' }, callback)
    .subscribe();
};

