import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Menu, Home, TrendingUp, Sun, Moon, Database, Cloud, AlertCircle, Save } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { Post } from './types';
import { INITIAL_TOPICS } from './constants';
import * as SupabaseService from './services/supabaseClient';

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);
  const [currentUserNickname, setCurrentUserNickname] = useState<string>('Guest');
  const [isConnected, setIsConnected] = useState(false);
  const [showConfig, setShowConfig] = useState(false);

  // Config State
  const [configUrl, setConfigUrl] = useState('');
  const [configKey, setConfigKey] = useState('');
  const [isConnecting, setIsConnecting] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('echo_theme');
      return saved === 'light' || saved === 'dark' ? saved : 'dark';
    }
    return 'dark';
  });

  const scrollRef = useRef<HTMLDivElement>(null);

  // Initialize Theme
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('echo_theme', theme);
  }, [theme]);

  // Initialize Supabase
  useEffect(() => {
    const client = SupabaseService.getSupabase();
    if (client) {
      setIsConnected(true);
      loadPosts();
    } else {
      setShowConfig(true);
    }
  }, []);

  const loadPosts = async () => {
    try {
      const remotePosts = await SupabaseService.fetchPosts();
      setPosts(remotePosts);
    } catch (e) {
      console.error("Failed to load posts", e);
    }
  };

  // Real-time Subscription
  useEffect(() => {
    if (!isConnected) return;

    const subscription = SupabaseService.subscribeToPosts((payload) => {
      // When a new post comes in via websocket
      if (payload.new) {
        // We could just append, but fetching ensures clean mapping
        // For efficiency in a real app, map the payload directly.
        // Here, we'll just reload top 10 to keep it synced perfectly
        loadPosts();
      }
    });

    return () => {
      subscription?.unsubscribe();
    };
  }, [isConnected]);

  const handleConnect = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsConnecting(true);
    const success = SupabaseService.initSupabase(configUrl, configKey);
    if (success) {
        setIsConnected(true);
        setShowConfig(false);
        await loadPosts();
    } else {
        alert("Invalid URL or Key");
    }
    setIsConnecting(false);
  };

  const handleDisconnect = () => {
    SupabaseService.disconnectSupabase();
    setIsConnected(false);
    setPosts([]);
    setShowConfig(true);
  };

  const handleUserPost = async (nickname: string, content: string, tags: string[]) => {
    setCurrentUserNickname(nickname);
    if (!isConnected) return;

    // Optimistically update UI
    const tempId = Date.now().toString();
    const tempPost: Post = {
        id: tempId,
        author: { nickname, avatarSeed: nickname, isAi: false },
        content,
        tags,
        timestamp: Date.now(),
        likes: 0,
        comments: []
    };
    setPosts(prev => [tempPost, ...prev]);

    // Send to DB
    try {
        await SupabaseService.createPost(nickname, content, tags);
        // We rely on the subscription to fix the ID and real data
    } catch (e) {
        console.error("Post failed", e);
        setPosts(prev => prev.filter(p => p.id !== tempId));
        alert("Failed to post. Check connection.");
    }
  };

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  // Calculate active users from loaded posts
  const activeUsers = useMemo(() => {
    const uniqueUsers = new Map();
    posts.forEach(post => {
      if (!uniqueUsers.has(post.author.nickname)) {
        uniqueUsers.set(post.author.nickname, post.author.avatarSeed);
      }
    });
    return Array.from(uniqueUsers.entries()).map(([nickname, seed]) => ({ nickname, seed }));
  }, [posts]);

  // Calculate trending from loaded posts
  const trendingTopics = useMemo(() => {
    const counts: Record<string, number> = {};
    posts.forEach(post => {
      post.tags.forEach(tag => {
        counts[tag] = (counts[tag] || 0) + 1;
      });
    });
    const sorted = Object.entries(counts).sort((a, b) => b[1] - a[1]);
    return sorted.length > 0 ? sorted.slice(0, 5).map(t => '#' + t[0]) : INITIAL_TOPICS;
  }, [posts]);

  return (
    <div className="min-h-screen flex justify-center transition-colors duration-300
                    bg-[#F5F5F5] text-neutral-900
                    dark:bg-[#000000] dark:text-white">

      <div className="flex w-full max-w-7xl h-screen">

        {/* Navigation Rail */}
        <nav className="hidden md:flex flex-col w-20 lg:w-72 shrink-0 pt-8 px-4 transition-colors border-r
                        bg-white border-neutral-200
                        dark:bg-[#000000] dark:border-[#1F1F1F]">

          <div className="mb-8 flex items-center justify-center lg:justify-start lg:pl-4">
             <span className="text-2xl font-bold tracking-tight">Echo</span>
          </div>

          <div className="space-y-2">
            <div className="flex items-center gap-4 px-4 py-4 rounded-full font-bold cursor-pointer transition-transform hover:scale-[1.02]
                            bg-black text-white
                            dark:bg-white dark:text-black">
               <Home size={24} />
               <span className="hidden lg:block">Feed</span>
            </div>

            <div className="flex items-center gap-4 px-4 py-4 rounded-full cursor-pointer transition-colors
                            text-neutral-500 hover:bg-neutral-100 hover:text-black
                            dark:text-neutral-500 dark:hover:bg-[#121212] dark:hover:text-white">
               <TrendingUp size={24} />
               <span className="hidden lg:block">Trending</span>
            </div>

            <button onClick={toggleTheme}
               className="flex items-center gap-4 px-4 py-4 rounded-full cursor-pointer transition-colors w-full text-left
                          text-neutral-500 hover:bg-neutral-100 hover:text-black
                          dark:text-neutral-500 dark:hover:bg-[#121212] dark:hover:text-white">
               {theme === 'dark' ? <Sun size={24} /> : <Moon size={24} />}
               <span className="hidden lg:block">{theme === 'dark' ? 'Light Mode' : 'Dark Mode'}</span>
            </button>
          </div>

          <div className="mt-auto mb-8 hidden lg:block">
            <div className="p-4 rounded-[24px] border
                            bg-neutral-50 border-neutral-200
                            dark:bg-[#0A0A0A] dark:border-[#1F1F1F]">
              <h3 className="text-sm font-semibold mb-4 text-neutral-500 dark:text-neutral-400">Trending Now</h3>
              <div className="flex flex-wrap gap-2">
                {trendingTopics.map((topic, i) => (
                  <span key={i} className="text-xs px-2 py-1 rounded-md cursor-pointer transition-colors
                                           bg-white text-neutral-700 hover:bg-black hover:text-white
                                           dark:bg-[#1F1F1F] dark:text-neutral-300 dark:hover:bg-white dark:hover:text-black">
                      {topic}
                  </span>
                ))}
              </div>
            </div>
          </div>
        </nav>

        {/* Main Content Area */}
        <main className="flex-1 flex flex-col h-full relative max-w-2xl mx-auto w-full">
          {/* Mobile Header */}
          <div className="md:hidden flex items-center justify-between p-4 border-b sticky top-0 z-20 transition-colors
                          bg-white border-neutral-200 text-black
                          dark:bg-[#000000] dark:border-[#1F1F1F] dark:text-white">
             <div className="flex items-center gap-2">
               <span className="text-xl font-bold tracking-tight">Echo</span>
             </div>
             <div className="flex gap-2">
                <button onClick={toggleTheme} className="p-2">
                  {theme === 'dark' ? <Sun size={24} /> : <Moon size={24} />}
                </button>
                <button className="p-2" onClick={() => setShowConfig(!showConfig)}>
                    <Menu size={24} />
                </button>
             </div>
          </div>

          <div 
            ref={scrollRef}
            className="flex-1 overflow-y-auto px-4 py-6 scroll-smooth"
          >
             <div className="max-w-xl mx-auto">
                {/* Configuration Panel (Collapsible) */}
                {showConfig && (
                    <div className="mb-6 p-6 rounded-[24px] border bg-neutral-50 border-neutral-200 dark:bg-[#121212] dark:border-neutral-800">
                        <div className="flex items-center gap-2 mb-4">
                            <Cloud className="text-blue-500" />
                            <h3 className="font-bold text-lg">Connect Cloud Database</h3>
