import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Menu, Home, TrendingUp, Sun, Moon, Database, Cloud, AlertCircle, Save, XCircle, Terminal } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { Post } from './types';
import { INITIAL_TOPICS } from './constants';
import * as SupabaseService from './services/supabaseClient';

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);
  const [currentUserNickname, setCurrentUserNickname] = useState<string>('Guest');
  const [isConnected, setIsConnected] = useState(false);
  const [showConfig, setShowConfig] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Config State
  const [configUrl, setConfigUrl] = useState('');
  const [configKey, setConfigKey] = useState('');
  const [isConnecting, setIsConnecting] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('echo_theme');
      return saved === 'light' || saved === 'dark' ? saved : 'dark';
    }
    return 'dark';
  });

  const scrollRef = useRef<HTMLDivElement>(null);

  // Initialize Theme
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('echo_theme', theme);
  }, [theme]);

  // Initialize Supabase
  useEffect(() => {
    const client = SupabaseService.getSupabase();
    if (client) {
      setIsConnected(true);
      loadPosts();
    } else {
      setShowConfig(true);
    }
  }, []);

  const loadPosts = async () => {
    try {
      setErrorMsg(null);
      const remotePosts = await SupabaseService.fetchPosts();
      setPosts(remotePosts);
    } catch (e: any) {
      console.error("Failed to load posts", e);
      // Supabase errors often come as objects with a message property
      const message = e.message || e.error_description || JSON.stringify(e);
      setErrorMsg(message);
    }
  };

  // Real-time Subscription
  useEffect(() => {
    if (!isConnected) return;

    const subscription = SupabaseService.subscribeToPosts((payload) => {
      if (payload.new) {
        loadPosts();
      }
    });

    return () => {
      subscription?.unsubscribe();
    };
  }, [isConnected]);

  const handleConnect = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsConnecting(true);
    setErrorMsg(null);

    // Basic validation
    if (!configUrl.includes('supabase.co')) {
        alert("URL must look like: https://your-project.supabase.co");
        setIsConnecting(false);
        return;
    }

    const success = SupabaseService.initSupabase(configUrl, configKey);
    if (success) {
        setIsConnected(true);
        // Try to fetch immediately to verify
        try {
            await SupabaseService.fetchPosts();
            setShowConfig(false);
            setPosts([]); // Clear previous state before reload
            await loadPosts();
        } catch (e: any) {
            console.error("Connection verification failed", e);
            const message = e.message || "Connected, but failed to fetch data. Check RLS policies.";
            setErrorMsg(message);
            // We still allow 'connected' state so they can see the error UI
        }
    } else {
        alert("Invalid URL or Key format");
    }
    setIsConnecting(false);
  };

  const handleDisconnect = () => {
    SupabaseService.disconnectSupabase();
    setIsConnected(false);
    setPosts([]);
    setErrorMsg(null);
    setShowConfig(true);
