  const handleUserPost = async (nickname: string, content: string, tags: string[]) => {
    setCurrentUserNickname(nickname);
    if (!isConnected) return;

    const tempId = Date.now().toString();
    const tempPost: Post = {
        id: tempId,
        author: { nickname, avatarSeed: nickname, isAi: false },
        content,
        tags,
        timestamp: Date.now(),
        likes: 0,
        comments: []
    };
