const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Ind5YXNmZHBleXpkaXF0cHBvb3hiIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjUwOTU1NjUsImV4cCI6MjA4MDY3MTU2NX0.i6QXXas9XSwyH9-LjJSn392gOygSIwW3nFapmAjx5qI';

export const MAX_POSTS_LIMIT = 100; // Hard limit to keep DB free and fast

// Initialize immediately
const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

export const getSupabase = () => supabase;

// Map DB row to App Post type
const mapRowToPost = (row: any): Post => ({
  id: row.id,
  author: {
    nickname: row.nickname,
    avatarSeed: row.avatar_seed,
    isAi: false
  },
  content: row.content,
  tags: row.tags || [],
  timestamp: new Date(row.created_at).getTime(),
  likes: row.likes,
  comments: [] // Comments would require another table, keeping simple for now
});

export const fetchPosts = async (): Promise<Post[]> => {
  const { data, error } = await supabase
    .from('posts')
    .select('*')
    .order('created_at', { ascending: false })
    .limit(MAX_POSTS_LIMIT);

  if (error) throw error;
  return (data || []).map(mapRowToPost);
};

export const createPost = async (nickname: string, content: string, tags: string[]): Promise<Post | null> => {
  // 1. Insert new post
  const { data, error } = await supabase
    .from('posts')
    .insert([{
      nickname,
      content,
      tags,
      avatar_seed: nickname,
      likes: 0
    }])
    .select()
    .single();

  if (error) throw error;

  // 2. Auto-Cleanup: Delete old posts to save space (Client-side trigger)
  cleanUpOldPosts(supabase);

  return mapRowToPost(data);
};

export const deletePost = async (id: string): Promise<void> => {
  const { error } = await supabase
    .from('posts')
    .delete()
    .eq('id', id);

  if (error) throw error;
};

const cleanUpOldPosts = async (client: SupabaseClient) => {
  try {
    // Check count
    const { count } = await client.from('posts').select('*', { count: 'exact', head: true });

    if (count !== null && count > MAX_POSTS_LIMIT) {
      // Find oldest posts
      const excess = count - MAX_POSTS_LIMIT;

      // We need to fetch IDs of oldest posts to delete them
      const { data: oldPosts } = await client
        .from('posts')
        .select('id')
        .order('created_at', { ascending: true })
        .limit(excess + 5); 

      if (oldPosts && oldPosts.length > 0) {
        const ids = oldPosts.map(p => p.id);
        await client.from('posts').delete().in('id', ids);
      }
    }
  } catch (e) {
    console.warn("Cleanup failed (likely permission issue, harmless)", e);
  }
};

export const toggleLike = async (postId: string, increment: boolean) => {
  const { data } = await supabase.from('posts').select('likes').eq('id', postId).single();
  if (data) {
    const newLikes = Math.max(0, data.likes + (increment ? 1 : -1));
    await supabase.from('posts').update({ likes: newLikes }).eq('id', postId);
  }
};

export const subscribeToPosts = (callback: (payload: any) => void) => {
  return supabase
    .channel('public:posts')
    .on('postgres_changes', { event: '*', schema: 'public', table: 'posts' }, callback)
    .subscribe();
};

import React, { useState } from 'react';
import { Send, Hash, Sparkles } from 'lucide-react';
import { Button } from './Button';

interface CreatePostProps {
  onPost: (nickname: string, content: string, tags: string[]) => void;
  defaultNickname: string;
}

export const CreatePost: React.FC<CreatePostProps> = ({ onPost, defaultNickname }) => {
  const [nickname, setNickname] = useState(defaultNickname);
  const [content, setContent] = useState('');
  const [tagInput, setTagInput] = useState('');
  const [isFocused, setIsFocused] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!nickname.trim() || !content.trim()) return;

    // 1. Process explicit tags from the input field
    // Split by comma or space, trim whitespace, remove leading #, remove empty strings
    const explicitTags = tagInput
      .split(/[\s,]+/) 
      .map(t => t.trim().replace(/^#/, '')) 
      .filter(t => t.length > 0);

    // 2. Auto-detect tags embedded in the content body (e.g., "Hello #world")
    const contentTags = content.match(/#[\w]+/g)?.map(t => t.replace('#', '')) || [];

    // 3. Merge and deduplicate
    const finalTags = [...new Set([...explicitTags, ...contentTags])];

    onPost(nickname, content, finalTags);
    setContent('');
    setTagInput('');
  };

  return (
    <div className={`
        rounded-[28px] p-4 mb-6 transition-all duration-300 border
        bg-white border-neutral-200 dark:bg-[#121212] dark:border-neutral-800
        ${isFocused ? 'shadow-lg shadow-black/5 dark:shadow-white/5 border-neutral-300 dark:border-neutral-700' : 'shadow-none'}
    `}>
      <form onSubmit={handleSubmit}>

        {/* Nickname Chip */}
        <div className="flex gap-3 mb-2">
            <div className="relative group">
                <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none">
                     <span className="text-xs text-neutral-500 font-medium">@</span>
                </div>
                <input
                    type="text"
                    value={nickname}
                    onChange={(e) => setNickname(e.target.value)}
                    placeholder="Nickname"
                    className="
                        rounded-lg pl-6 pr-3 py-1.5 text-sm font-medium outline-none transition-colors w-32
                        bg-neutral-50 text-neutral-900 border border-neutral-200 focus:border-black
                        dark:bg-[#000000] dark:text-neutral-200 dark:border-neutral-800 dark:focus:border-white
                    "
                    required
                />
            </div>
        </div>

        {/* Text Area */}
        <div className="relative p-2">
          <textarea
            value={content}
            onChange={(e) => setContent(e.target.value)}
            onFocus={() => setIsFocused(true)}
            onBlur={() => setIsFocused(false)}
            placeholder="Share your thoughts..."
            className="w-full bg-transparent border-none focus:ring-0 resize-none min-h-[100px] text-base leading-relaxed p-0
                       text-neutral-900 placeholder-neutral-400
                       dark:text-white dark:placeholder-neutral-600"
            required
          />
        </div>

        {/* Tag Input (Collapsible) */}
        <div className={`transition-all duration-300 overflow-hidden ${isFocused || content ? 'max-h-20 opacity-100 mt-2' : 'max-h-0 opacity-0'}`}>
          <div className="flex items-center gap-2 rounded-lg px-3 py-2 mx-2 border
                          bg-neutral-50 border-neutral-200
                          dark:bg-[#000000] dark:border-neutral-800">
            <Hash size={14} className="text-neutral-400 dark:text-neutral-500" />
            <input
              type="text"
              value={tagInput}
              onChange={(e) => setTagInput(e.target.value)}
              placeholder="Tags (space separated, e.g. tech random)"
              className="bg-transparent border-none text-sm focus:ring-0 flex-1 p-0
                         text-neutral-700 placeholder-neutral-400
                         dark:text-neutral-300 dark:placeholder-neutral-700"
            />
          </div>
        </div>

        {/* Action Bar */}
        <div className="flex justify-between items-center mt-4 px-2">
          <div className="flex gap-1">
             <button 
                type="button" 
                className="p-2 rounded-full transition-colors
                           text-neutral-500 hover:bg-neutral-100 hover:text-black
                           dark:text-neutral-400 dark:hover:bg-white/10 dark:hover:text-white" 
                title="Generate AI Suggestion"
             >
                <Sparkles size={20} />
             </button>
          </div>

          <Button 
            type="submit" 
            variant="primary"
            disabled={!content.trim() || !nickname.trim()}
          >
            <span>Post</span>
            <Send size={16} />
          </Button>
        </div>
      </form>
    </div>
  );
};

