alter table posts enable row level security;

-- DROP EXISTING POLICIES TO RESET PERMISSIONS
drop policy if exists "Public Access" on posts;
drop policy if exists "Enable read access for all users" on posts;
drop policy if exists "Enable insert for all users" on posts;
drop policy if exists "Enable delete for all users" on posts;

-- CREATE ONE PERMISSIVE POLICY FOR ALL OPERATIONS (SELECT, INSERT, UPDATE, DELETE)
create policy "Public Access" on posts 
  for all 
  using (true) 
  with check (true);`;

    navigator.clipboard.writeText(sql);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
