        <nav className="hidden md:flex flex-col w-20 lg:w-72 shrink-0 pt-8 px-4 transition-colors border-r
                        bg-white border-neutral-200
                        dark:bg-[#000000] dark:border-[#1F1F1F]">

          <div className="mb-8 flex items-center justify-center lg:justify-start lg:pl-4">
             <span className="text-2xl font-bold tracking-tight">Echo</span>
          </div>

          <div className="space-y-2">
            <div onClick={clearFilter} 
                 className={`flex items-center gap-4 px-4 py-4 rounded-full font-bold cursor-pointer transition-transform hover:scale-[1.02]
                            ${!selectedTag ? 'bg-black text-white dark:bg-white dark:text-black' : 'text-neutral-500 hover:bg-neutral-100 dark:hover:bg-[#121212] hover:text-black dark:hover:text-white'}`}>
               <Home size={24} />
               <span className="hidden lg:block">Feed</span>
            </div>

            <div className={`flex items-center gap-4 px-4 py-4 rounded-full cursor-pointer transition-colors
                            ${selectedTag ? 'bg-black text-white dark:bg-white dark:text-black' : 'text-neutral-500 hover:bg-neutral-100 dark:hover:bg-[#121212] hover:text-black dark:hover:text-white'}`}>
               <TrendingUp size={24} />
               <span className="hidden lg:block">Trending</span>
            </div>

            <button onClick={toggleTheme}
