          <div className="mt-auto mb-8 hidden lg:block">
            <div className="p-4 rounded-[24px] border
                            bg-neutral-50 border-neutral-200
                            dark:bg-[#0A0A0A] dark:border-[#1F1F1F]">
              <h3 className="text-sm font-semibold mb-4 text-neutral-500 dark:text-neutral-400">Trending Now</h3>
