                    {filteredPosts.length === 0 && !isLoading && !errorMsg ? (
                        <div className="text-center py-32 opacity-50">
                            <div className="text-6xl mb-4 grayscale filter contrast-200">
                                {selectedTag ? '🔍' : '🌍'}
                            </div>
                            <h2 className="text-xl font-medium mb-2">
                                {selectedTag ? 'No posts found' : 'World is Quiet'}
                            </h2>
                            <p className="text-sm text-neutral-500">
