                        <div className="w-2 h-2 rounded-full bg-current"></div>
                        <span className="font-medium text-xs">Connected</span>
                    </div>
                    <p className="opacity-70 text-xs">
                       Identity: Shadow UUID <br/>
                       ID: {SupabaseService.SHADOW_USER_ID.slice(0,8)}...
