import { INITIAL_TOPICS } from './constants';
import * as SupabaseService from './services/supabaseClient';

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);

  // Persist nickname
  const [currentUserNickname, setCurrentUserNickname] = useState<string>(() => {
    if (typeof window !== 'undefined') {
        return localStorage.getItem('echo_nickname') || 'Guest';
    }
    return 'Guest';
  });

  const [authUserId, setAuthUserId] = useState<string | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [copied, setCopied] = useState(false);
  const [selectedTag, setSelectedTag] = useState<string | null>(null);

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('echo_theme');
      return saved === 'light' || saved === 'dark' ? saved : 'light';
    }
    return 'light';
  });

  const scrollRef = useRef<HTMLDivElement>(null);

  // Initialize Theme
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('echo_theme', theme);
  }, [theme]);

  // Save nickname whenever it changes
  useEffect(() => {
    localStorage.setItem('echo_nickname', currentUserNickname);
  }, [currentUserNickname]);

  // Init Auth and Load Data
  useEffect(() => {
    const init = async () => {
        try {
            setIsAuthLoading(true);
            const uid = await SupabaseService.initializeAuth();
            setAuthUserId(uid);
            await loadPosts();
        } catch (e: any) {
            console.error("Initialization failed", e);
            if (e.message?.includes("Anonymous sign-ins are disabled")) {
                setErrorMsg("Anonymous Auth is disabled in Supabase. Please enable it in Authentication > Providers.");
            } else {
                setErrorMsg(getErrorMessage(e));
            }
        } finally {
            setIsAuthLoading(false);
            setIsLoading(false);
        }
    };
    init();
  }, []);

  const getErrorMessage = (e: any) => {
    if (!e) return "Unknown error";
    if (e.code && e.message) return `Error ${e.code}: ${e.message}`;
    if (e.message) return e.message;
    if (e.error_description) return e.error_description;
    if (typeof e === 'string') return e;
    try { return JSON.stringify(e, null, 2); } catch { return "Unknown error object"; }
  };

  const loadPosts = async () => {
    try {
      const remotePosts = await SupabaseService.fetchPosts();
      setPosts(remotePosts);
    } catch (e: any) {
      console.error("Failed to load posts", e);
      setErrorMsg(getErrorMessage(e));
    }
  };

  // Real-time Subscription
  useEffect(() => {
    const subscription = SupabaseService.subscribeToPosts((payload) => {
      if (payload.eventType === 'INSERT' || payload.eventType === 'DELETE') {
        loadPosts();
      }
    });

    return () => {
      subscription?.unsubscribe();
    };
  }, []);

  const handleUserPost = async (nickname: string, content: string, tags: string[]) => {
    if (!authUserId) {
        alert("Authentication is still initializing. Please wait.");
        return;
    }
    setCurrentUserNickname(nickname);

    const tempId = Date.now().toString(); // Temporary ID for optimistic UI
    const tempPost: Post = {
        id: tempId,
        author: { 
            nickname, 
            avatarSeed: nickname, 
            isAi: false,
            userId: authUserId
        },
        content,
        tags,
        timestamp: Date.now(),
        likes: 0,
        comments: []
    };

    // Optimistic update
    setPosts(prev => [tempPost, ...prev]);

    try {
        const realPost = await SupabaseService.createPost(nickname, content, tags);
        if (realPost) {
            setPosts(prev => prev.map(p => p.id === tempId ? realPost : p));
        }
    } catch (e: any) {
        console.error("Post failed", e);
        setPosts(prev => prev.filter(p => p.id !== tempId)); 
        alert(`Failed to post: ${getErrorMessage(e)}`);
    }
  };

  const handleDeletePost = async (postId: string) => {
    setPosts(prev => prev.filter(p => p.id !== postId));

    if (!postId.includes('-') && /^\d+$/.test(postId)) {
        return;
    }

    try {
        await SupabaseService.deletePost(postId);
    } catch (e: any) {
        console.error("Delete failed", e);
        alert(`Failed to delete: ${getErrorMessage(e)}`);
        loadPosts();
    }
  };

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const copySQL = () => {
    // STANDARD SQL for Supabase Auth
    const sql = `
-- 1. Create Table
create table if not exists posts (
  id uuid default gen_random_uuid() primary key,
  nickname text not null,
  content text not null,
  tags text[] default '{}',
  likes int default 0,
  avatar_seed text,
  user_id uuid, -- Matches auth.uid()
  created_at timestamptz default now()
);

-- 2. Index
create index if not exists idx_posts_user_id on posts(user_id);

-- 3. Enable RLS
alter table posts enable row level security;

-- 4. Clean old policies
drop policy if exists "Public Access" on posts;
drop policy if exists "Shadow Insert" on posts;
drop policy if exists "Shadow Delete" on posts;
drop policy if exists "Public Read" on posts;
drop policy if exists "Auth Insert" on posts;
drop policy if exists "Owner Delete" on posts;

-- 5. CREATE STANDARD AUTH POLICIES
-- A. Everyone can read
create policy "Public Read" on posts for select using (true);

-- B. Authenticated users (Anonymous included) can insert
-- They must set user_id to their own auth.uid()
create policy "Auth Insert" on posts for insert with check (
  auth.uid() = user_id
);

-- C. Users can only delete their own posts
create policy "Owner Delete" on posts for delete using (
  auth.uid() = user_id
);
`;

    navigator.clipboard.writeText(sql);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleTagClick = (tag: string) => {
      const rawTag = tag.replace(/^#/, '');
