                    </p>
               </div>
            </div>
        </aside>

      </div>
    </div>
  );
}

import { createClient, SupabaseClient } from '@supabase/supabase-js';
import { v4 as uuidv4 } from 'uuid';
import { Post } from '../types';

// Hardcoded configuration
const SUPABASE_URL = 'https://wyasfdpeyzdiqtppooxb.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Ind5YXNmZHBleXpkaXF0cHBvb3hiIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjUwOTU1NjUsImV4cCI6MjA4MDY3MTU2NX0.i6QXXas9XSwyH9-LjJSn392gOygSIwW3nFapmAjx5qI';

export const MAX_POSTS_LIMIT = 100;

// --- 1. SHADOW IDENTITY (FALLBACK) ---
// Used when standard Auth is disabled/fails.
const getShadowIdentity = (): string => {
  if (typeof window === 'undefined') return '';
  let id = localStorage.getItem('shadow_user_id');
  if (!id) {
    id = uuidv4();
    localStorage.setItem('shadow_user_id', id);
  }
  return id;
};

export const SHADOW_USER_ID = getShadowIdentity();

// --- 2. INITIALIZE CLIENT ---
const supabase = createClient(SUPABASE_URL, SUPABASE_KEY, {
  global: {
    headers: {
      // We always inject this header. 
      // If using JWT (Auth), RLS ignores it. 
      // If JWT is missing, RLS can optionally use this for Shadow Mode.
      'x-shadow-user-id': SHADOW_USER_ID 
    }
  }
});

export const getSupabase = () => supabase;

// --- 3. AUTHENTICATION & SESSION MANAGEMENT ---

let isUsingShadowMode = false;

export const initializeAuth = async (): Promise<string> => {
  try {
    // A. Check for existing active session (JWT present)
    const { data: { session } } = await supabase.auth.getSession();

    if (session?.user) {
      console.log("[Echo] Restored valid session:", session.user.id);
      return session.user.id;
    }

    // B. Attempt Anonymous Sign-in
    console.log("[Echo] Attempting Anonymous Sign-in...");
    const { data, error } = await supabase.auth.signInAnonymously();

    if (error) {
      // Gracefully handle "Disabled" state
      if (error.message.includes("Anonymous sign-ins are disabled") || error.status === 400 || error.code === 'anonymous_provider_disabled') {
        console.warn("[Echo] Anonymous Auth is disabled on this project. Switching to Shadow Mode (Header-based).");
        isUsingShadowMode = true;
        return SHADOW_USER_ID;
      }
      throw error;
    }

    if (data.user) {
        console.log("[Echo] Anonymous Sign-in successful:", data.user.id);
        return data.user.id;
    }

    return SHADOW_USER_ID;

  } catch (e: any) {
    console.error("[Echo] Auth initialization encountered an error:", e.message);
    // Fallback to Shadow Mode to keep app functional
    isUsingShadowMode = true;
    return SHADOW_USER_ID;
  }
};

/**
 * reliable way to get the ID intended for DB operations.
 * Prioritizes actual Auth Session ID, falls back to Shadow ID.
 */
export const getEffectiveUserId = async (): Promise<string> => {
  // 1. Try to get real session user
  const { data: { session } } = await supabase.auth.getSession();
  if (session?.user) {
      return session.user.id;
  }
  // 2. Fallback
  return SHADOW_USER_ID;
};

// --- DATA MAPPING ---

const mapRowToPost = (row: any): Post => ({
  id: row.id,
  author: {
    nickname: row.nickname,
    avatarSeed: row.avatar_seed,
    isAi: false,
    userId: row.user_id 
  },
  content: row.content,
  tags: row.tags || [],
  timestamp: new Date(row.created_at).getTime(),
  likes: row.likes,
  comments: []
});

// --- API METHODS ---

export const fetchPosts = async (): Promise<Post[]> => {
  const { data, error } = await supabase
    .from('posts')
    .select('*')
    .order('created_at', { ascending: false })
    .limit(MAX_POSTS_LIMIT);

  if (error) throw error;
  return (data || []).map(mapRowToPost);
};

export const createPost = async (nickname: string, content: string, tags: string[]): Promise<Post | null> => {
  // 1. Validate Session / Identity
  const userId = await getEffectiveUserId();

  // 2. Insert
  // If we have a session, supabase client automatically attaches `Authorization: Bearer <token>`
  // RLS Policy `auth.uid() = user_id` will pass.
  // If no session, we rely on `x-shadow-user-id` header and Universal Policy.
  const { data, error } = await supabase
    .from('posts')
    .insert([{
      nickname,
      content,
      tags,
      avatar_seed: nickname,
      likes: 0,
      user_id: userId // MUST match the authenticated user (or shadow ID)
    }])
    .select()
    .single();

  if (error) {
      console.error("[Echo] Create Post Failed:", error);
      throw error;
  }

  // 3. Cleanup
  cleanUpOldPosts(supabase);

  return mapRowToPost(data);
};

export const deletePost = async (id: string): Promise<void> => {
  console.log(`[Echo] Requesting delete for post ${id}...`);

  // 1. Identify User
  const userId = await getEffectiveUserId();

  // 2. Optional: Pre-flight Ownership Check (Client-side)
  // This helps give a better error message before the RLS block
  // (We skip this if strictly optimizing for latency, but good for UX)
  /*
  const { data: postToCheck } = await supabase
    .from('posts')
    .select('user_id')
    .eq('id', id)
    .single();

  if (postToCheck && postToCheck.user_id !== userId) {
      throw new Error("Ownership mismatch: You cannot delete this post.");
  }
  */

  // 3. Perform Delete
  // RLS will enforce security on the server.
  const { error, count } = await supabase
    .from('posts')
    .delete({ count: 'exact' })
    .eq('id', id); // We rely on RLS policy "auth.uid() = user_id" to filter

  if (error) {
      console.error("[Echo] Delete Failed:", error);
      throw error;
  }

  if (count === 0) {
      console.warn(`[Echo] Delete returned 0 rows.`);
      // This usually means the row exists but RLS hid it from the delete operation
      // OR the row was already gone.
      throw new Error("Could not delete post. You might not be the owner, or it was already deleted.");
  } else {
      console.log(`[Echo] Successfully deleted ${count} post(s).`);
  }
};

const cleanUpOldPosts = async (client: SupabaseClient) => {
  try {
    const { count } = await client.from('posts').select('*', { count: 'exact', head: true });

    if (count !== null && count > MAX_POSTS_LIMIT) {
      const excess = count - MAX_POSTS_LIMIT;
      const { data: oldPosts } = await client
        .from('posts')
        .select('id')
        .order('created_at', { ascending: true })
        .limit(excess + 5); 

      if (oldPosts && oldPosts.length > 0) {
        const ids = oldPosts.map(p => p.id);
        await client.from('posts').delete().in('id', ids);
      }
    }
  } catch (e) {
    // Ignore cleanup errors
  }
};

export const toggleLike = async (postId: string, increment: boolean) => {
  const { data } = await supabase.from('posts').select('likes').eq('id', postId).single();
  if (data) {
    const newLikes = Math.max(0, data.likes + (increment ? 1 : -1));
    await supabase.from('posts').update({ likes: newLikes }).eq('id', postId);
  }
};

export const subscribeToPosts = (callback: (payload: any) => void) => {
  return supabase
    .channel('public:posts')
    .on('postgres_changes', { event: '*', schema: 'public', table: 'posts' }, callback)
    .subscribe();
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Menu, Home, TrendingUp, Sun, Moon, Database, XCircle, Terminal, RefreshCw, Copy, Check, Hash, X, Lock } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { Post } from './types';
import { INITIAL_TOPICS } from './constants';
import * as SupabaseService from './services/supabaseClient';

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);

  const [currentUserNickname, setCurrentUserNickname] = useState<string>(() => {
    if (typeof window !== 'undefined') {
        return localStorage.getItem('echo_nickname') || 'Guest';
    }
    return 'Guest';
  });

  const [authUserId, setAuthUserId] = useState<string | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [copied, setCopied] = useState(false);
  const [selectedTag, setSelectedTag] = useState<string | null>(null);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('echo_theme');
      return saved === 'light' || saved === 'dark' ? saved : 'light';
    }
    return 'light';
  });

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('echo_theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('echo_nickname', currentUserNickname);
  }, [currentUserNickname]);

  // Init Auth and Load Data
  useEffect(() => {
    const init = async () => {
        try {
            setIsAuthLoading(true);
            // This now handles fallback internally so it shouldn't throw on 'disabled' error
            const uid = await SupabaseService.initializeAuth();
            setAuthUserId(uid);
            await loadPosts();
        } catch (e: any) {
            console.error("Critical Init Failure", e);
            // We only show the error banner if it's truly catastrophic (e.g., network down)
            // Auth failures are now handled gracefully by falling back to shadow mode
            setErrorMsg(getErrorMessage(e));
        } finally {
            setIsAuthLoading(false);
            setIsLoading(false);
        }
    };
    init();
  }, []);

  const getErrorMessage = (e: any) => {
    if (!e) return "Unknown error";
    if (e.code && e.message) return `Error ${e.code}: ${e.message}`;
    if (e.message) return e.message;
    return typeof e === 'string' ? e : JSON.stringify(e);
  };

  const loadPosts = async () => {
    try {
      const remotePosts = await SupabaseService.fetchPosts();
      setPosts(remotePosts);
    } catch (e: any) {
      console.error("Failed to load posts", e);
      // Don't show error if it's just empty or network blip on first load
      if (posts.length === 0) setErrorMsg(getErrorMessage(e));
    }
  };

  useEffect(() => {
    const subscription = SupabaseService.subscribeToPosts((payload) => {
      if (payload.eventType === 'INSERT' || payload.eventType === 'DELETE') {
        loadPosts();
      }
    });
    return () => { subscription?.unsubscribe(); };
  }, []);

  const handleUserPost = async (nickname: string, content: string, tags: string[]) => {
    if (!authUserId) return;
    setCurrentUserNickname(nickname);

    const tempId = Date.now().toString(); 
    const tempPost: Post = {
        id: tempId,
        author: { 
            nickname, 
            avatarSeed: nickname, 
            isAi: false,
            userId: authUserId
        },
        content,
        tags,
        timestamp: Date.now(),
        likes: 0,
        comments: []
    };

    setPosts(prev => [tempPost, ...prev]);

    try {
        const realPost = await SupabaseService.createPost(nickname, content, tags);
        if (realPost) {
            setPosts(prev => prev.map(p => p.id === tempId ? realPost : p));
        }
    } catch (e: any) {
        console.error("Post failed", e);
        setPosts(prev => prev.filter(p => p.id !== tempId)); 
        alert(`Failed to post. Ensure your DB Policies are updated.\n\n${getErrorMessage(e)}`);
    }
  };

  const handleDeletePost = async (postId: string) => {
    // 1. Optimistic Update (Remove from UI immediately)
    setPosts(prev => prev.filter(p => p.id !== postId));

    // If it's a temp ID (numbers only), skip server call
    if (!postId.includes('-') && /^\d+$/.test(postId)) return;

    try {
        await SupabaseService.deletePost(postId);
    } catch (e: any) {
        console.error("Delete failed", e);
        // 2. Rollback on failure
        alert(`Failed to delete. You might not be the owner.\n\n${getErrorMessage(e)}`);
        loadPosts();
    }
  };

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const copySQL = () => {
    // UNIVERSAL SQL: Works with BOTH Supabase Auth AND Shadow Identity
    const sql = `
-- 1. Table Setup
create table if not exists posts (
  id uuid default gen_random_uuid() primary key,
  nickname text not null,
  content text not null,
  tags text[] default '{}',
  likes int default 0,
  avatar_seed text,
  user_id uuid,
  created_at timestamptz default now()
);

-- 2. Performance Index
create index if not exists idx_posts_user_id on posts(user_id);

-- 3. Security
alter table posts enable row level security;

-- 4. Clean Slate (Remove old conflicting policies)
drop policy if exists "Universal Read" on posts;
drop policy if exists "Universal Insert" on posts;
drop policy if exists "Universal Delete" on posts;
-- (Legacy cleanup)
drop policy if exists "Public Access" on posts;
drop policy if exists "Shadow Insert" on posts;
drop policy if exists "Shadow Delete" on posts;
drop policy if exists "Auth Insert" on posts;
drop policy if exists "Owner Delete" on posts;

-- 5. UNIVERSAL POLICIES (Hybrid Auth)
-- These policies handle BOTH Authenticated Users (JWT) and Shadow Users (Header)

-- A. Read: Everyone
create policy "Universal Read" on posts for select using (true);

-- B. Insert: Allow if ID matches Auth UID OR Shadow Header
create policy "Universal Insert" on posts for insert with check (
  (auth.uid() IS NOT NULL AND auth.uid() = user_id)
  OR
  (auth.uid() IS NULL AND (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)
);

-- C. Delete: Allow if ID matches Auth UID OR Shadow Header
create policy "Universal Delete" on posts for delete using (
  (auth.uid() IS NOT NULL AND auth.uid() = user_id)
  OR
  (auth.uid() IS NULL AND (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)
);
`;

    navigator.clipboard.writeText(sql);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleTagClick = (tag: string) => {
      const rawTag = tag.replace(/^#/, '');
      setSelectedTag(rawTag);
      if (scrollRef.current) scrollRef.current.scrollTop = 0;
  };

  const clearFilter = () => setSelectedTag(null);

  const filteredPosts = useMemo(() => {
      if (!selectedTag) return posts;
      return posts.filter(post => 
          post.tags.some(t => t.toLowerCase() === selectedTag.toLowerCase())
      );
  }, [posts, selectedTag]);

  const activeUsers = useMemo(() => {
    const uniqueUsers = new Map();
    posts.forEach(post => {
      if (!uniqueUsers.has(post.author.nickname)) {
        uniqueUsers.set(post.author.nickname, post.author.avatarSeed);
      }
    });
    return Array.from(uniqueUsers.entries()).map(([nickname, seed]) => ({ nickname, seed }));
  }, [posts]);

  const trendingTopics = useMemo(() => {
    const counts: Record<string, number> = {};
    posts.forEach(post => post.tags.forEach(tag => counts[tag] = (counts[tag] || 0) + 1));
    const sorted = Object.entries(counts).sort((a, b) => b[1] - a[1]);
    return sorted.length > 0 ? sorted.slice(0, 5).map(t => '#' + t[0]) : INITIAL_TOPICS;
  }, [posts]);

  // Check ownership matches our current ID (whether Auth or Shadow)
  const isOwner = (post: Post) => {
    if (!authUserId) return false;
    return post.author.userId === authUserId;
  };

  return (
    <div className="min-h-screen flex justify-center transition-colors duration-300
                    bg-[#F5F5F5] text-neutral-900
                    dark:bg-[#000000] dark:text-white">

      <div className="flex w-full max-w-7xl h-screen">

        {/* Navigation Rail */}
        <nav className="hidden md:flex flex-col w-20 lg:w-72 shrink-0 pt-8 px-4 transition-colors border-r
                        bg-white border-neutral-200
                        dark:bg-[#000000] dark:border-[#1F1F1F]">

          <div className="mb-8 flex items-center justify-center lg:justify-start lg:pl-4">
             <span className="text-2xl font-bold tracking-tight">Echo</span>
          </div>

          <div className="space-y-2">
            <div onClick={clearFilter} 
                 className={`flex items-center gap-4 px-4 py-4 rounded-full font-bold cursor-pointer transition-transform hover:scale-[1.02]
                            ${!selectedTag ? 'bg-black text-white dark:bg-white dark:text-black' : 'text-neutral-500 hover:bg-neutral-100 dark:hover:bg-[#121212] hover:text-black dark:hover:text-white'}`}>
               <Home size={24} />
               <span className="hidden lg:block">Feed</span>
            </div>

            <div className={`flex items-center gap-4 px-4 py-4 rounded-full cursor-pointer transition-colors
                            ${selectedTag ? 'bg-black text-white dark:bg-white dark:text-black' : 'text-neutral-500 hover:bg-neutral-100 dark:hover:bg-[#121212] hover:text-black dark:hover:text-white'}`}>
               <TrendingUp size={24} />
               <span className="hidden lg:block">Trending</span>
            </div>

            <button onClick={toggleTheme}
               className="flex items-center gap-4 px-4 py-4 rounded-full cursor-pointer transition-colors w-full text-left
                          text-neutral-500 hover:bg-neutral-100 hover:text-black
                          dark:text-neutral-500 dark:hover:bg-[#121212] dark:hover:text-white">
               {theme === 'dark' ? <Sun size={24} /> : <Moon size={24} />}
               <span className="hidden lg:block">{theme === 'dark' ? 'Light Mode' : 'Dark Mode'}</span>
            </button>
          </div>

          <div className="mt-auto mb-8 hidden lg:block">
            <div className="p-4 rounded-[24px] border
                            bg-neutral-50 border-neutral-200
                            dark:bg-[#0A0A0A] dark:border-[#1F1F1F]">
              <h3 className="text-sm font-semibold mb-4 text-neutral-500 dark:text-neutral-400">Trending Now</h3>
              <div className="flex flex-wrap gap-2">
                {trendingTopics.map((topic, i) => (
                  <span key={i} 
                        onClick={() => handleTagClick(topic)}
                        className={`text-xs px-2 py-1 rounded-md cursor-pointer transition-colors
                                   ${selectedTag && topic.toLowerCase().includes(selectedTag.toLowerCase()) 
                                        ? 'bg-black text-white dark:bg-white dark:text-black' 
                                        : 'bg-white text-neutral-700 hover:bg-black hover:text-white dark:bg-[#1F1F1F] dark:text-neutral-300 dark:hover:bg-white dark:hover:text-black'
                                   }`}>
                      {topic}
                  </span>
                ))}
              </div>
            </div>

            <button 
                onClick={copySQL}
                className="mt-4 flex items-center gap-2 text-xs text-neutral-400 hover:text-black dark:hover:text-white transition-colors"
            >
                <Database size={12} />
                <span>Fix Database Perms (Universal)</span>
                {copied ? <Check size={12} className="text-green-500" /> : null}
            </button>
          </div>
        </nav>

        {/* Main Content Area */}
