const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Ind5YXNmZHBleXpkaXF0cHBvb3hiIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjUwOTU1NjUsImV4cCI6MjA4MDY3MTU2NX0.i6QXXas9XSwyH9-LjJSn392gOygSIwW3nFapmAjx5qI';

export const MAX_POSTS_LIMIT = 100;

// --- 1. SHADOW IDENTITY (FALLBACK) ---
const getShadowIdentity = (): string => {
  if (typeof window === 'undefined') return '';
  let id = localStorage.getItem('shadow_user_id');
  if (!id) {
    id = uuidv4();
    localStorage.setItem('shadow_user_id', id);
  }
  return id;
};

export const SHADOW_USER_ID = getShadowIdentity();

// --- 2. INITIALIZE CLIENT ---
const supabase = createClient(SUPABASE_URL, SUPABASE_KEY, {
  global: {
    headers: {
      'x-shadow-user-id': SHADOW_USER_ID 
    }
  }
});

export const getSupabase = () => supabase;

// --- 3. AUTHENTICATION ---

let isUsingShadowMode = false;

export const initializeAuth = async (): Promise<string> => {
  try {
    const { data: { session } } = await supabase.auth.getSession();

    if (session?.user) {
      console.log("[Echo] Restored valid session:", session.user.id);
      return session.user.id;
    }

    console.log("[Echo] Attempting Anonymous Sign-in...");
    const { data, error } = await supabase.auth.signInAnonymously();

    if (error) {
      if (error.message.includes("Anonymous sign-ins are disabled") || error.status === 400 || error.code === 'anonymous_provider_disabled') {
        console.warn("[Echo] Anonymous Auth disabled. Switching to Shadow Mode.");
        isUsingShadowMode = true;
        return SHADOW_USER_ID;
      }
      throw error;
    }

    if (data.user) {
        return data.user.id;
    }

    return SHADOW_USER_ID;

  } catch (e: any) {
    console.error("[Echo] Auth initialization error:", e.message);
    isUsingShadowMode = true;
    return SHADOW_USER_ID;
  }
};

export const getEffectiveUserId = async (): Promise<string> => {
  const { data: { session } } = await supabase.auth.getSession();
  if (session?.user) {
      return session.user.id;
  }
  return SHADOW_USER_ID;
};

// --- DATA MAPPING ---

const mapRowToComment = (row: any): Comment => ({
  id: row.id,
  author: {
    nickname: row.nickname,
    avatarSeed: row.avatar_seed,
    isAi: false, // Assuming all DB comments are human for now
    userId: row.user_id
  },
  content: row.content,
  timestamp: new Date(row.created_at).getTime(),
  likes: 0 // Not implemented in DB yet
});

const mapRowToPost = (row: any): Post => ({
  id: row.id,
  author: {
    nickname: row.nickname,
    avatarSeed: row.avatar_seed,
    isAi: false,
    userId: row.user_id 
  },
  content: row.content,
  tags: row.tags || [],
  timestamp: new Date(row.created_at).getTime(),
  likes: row.likes,
  comments: (row.comments || []).map(mapRowToComment).sort((a: Comment, b: Comment) => a.timestamp - b.timestamp)
});

// --- API METHODS ---

export const fetchPosts = async (): Promise<Post[]> => {
  // We fetch posts AND their associated comments
  const { data, error } = await supabase
    .from('posts')
    .select(`
      *,
      comments (
        id,
        content,
        nickname,
        avatar_seed,
        user_id,
        created_at
      )
    `)
    .order('created_at', { ascending: false })
    .limit(MAX_POSTS_LIMIT);

  if (error) throw error;
  return (data || []).map(mapRowToPost);
};

export const createPost = async (nickname: string, content: string, tags: string[]): Promise<Post | null> => {
  const userId = await getEffectiveUserId();

  const { data, error } = await supabase
    .from('posts')
    .insert([{
      nickname,
      content,
      tags,
      avatar_seed: nickname,
      likes: 0,
      user_id: userId
    }])
    .select()
    .single();

  if (error) {
      console.error("[Echo] Create Post Failed:", error);
      throw error;
  }

  cleanUpOldPosts(supabase);
  // Return post with empty comments array initially
  return mapRowToPost({ ...data, comments: [] });
};

export const deletePost = async (id: string): Promise<void> => {
  console.log(`[Echo] Requesting delete for post ${id}...`);

  const { error, count } = await supabase
    .from('posts')
    .delete({ count: 'exact' })
    .eq('id', id);

  if (error) {
      console.error("[Echo] Delete Failed:", error);
      throw error;
  }

  if (count === 0) {
      throw new Error("Could not delete post. You might not be the owner, or it was already deleted.");
  }
};

// --- COMMENTS ---

export const createComment = async (postId: string, content: string, nickname: string): Promise<Comment> => {
  const userId = await getEffectiveUserId();

  const { data, error } = await supabase
    .from('comments')
    .insert([{
      post_id: postId,
      content,
      nickname,
      avatar_seed: nickname,
      user_id: userId
    }])
    .select()
    .single();

  if (error) {
    console.error("[Echo] Create Comment Failed:", error);
    throw error;
  }

  return mapRowToComment(data);
};

export const deleteComment = async (commentId: string): Promise<void> => {
  console.log(`[Echo] Deleting comment ${commentId}...`);

  const { error, count } = await supabase
    .from('comments')
    .delete({ count: 'exact' })
    .eq('id', commentId);

  if (error) throw error;

  if (count === 0) {
    throw new Error("Could not delete comment. You might not be the owner.");
  }
};

const cleanUpOldPosts = async (client: SupabaseClient) => {
  try {
    const { count } = await client.from('posts').select('*', { count: 'exact', head: true });

    if (count !== null && count > MAX_POSTS_LIMIT) {
      const excess = count - MAX_POSTS_LIMIT;
      const { data: oldPosts } = await client
        .from('posts')
        .select('id')
        .order('created_at', { ascending: true })
        .limit(excess + 5); 

      if (oldPosts && oldPosts.length > 0) {
        const ids = oldPosts.map(p => p.id);
        await client.from('posts').delete().in('id', ids);
      }
    }
  } catch (e) {
    // Ignore cleanup errors
  }
};

export const toggleLike = async (postId: string, increment: boolean) => {
  const { data } = await supabase.from('posts').select('likes').eq('id', postId).single();
  if (data) {
    const newLikes = Math.max(0, data.likes + (increment ? 1 : -1));
    await supabase.from('posts').update({ likes: newLikes }).eq('id', postId);
  }
};

export const subscribeToPosts = (callback: (payload: any) => void) => {
  return supabase
    .channel('public:posts_and_comments')
    .on('postgres_changes', { event: '*', schema: 'public', table: 'posts' }, callback)
    .on('postgres_changes', { event: '*', schema: 'public', table: 'comments' }, callback)
    .subscribe();
};

import React, { useState, useEffect, useRef } from 'react';
import { Heart, MessageCircle, Share2, MoreVertical, Trash2, Send, X } from 'lucide-react';
import { Post, Comment } from '../types';
import { DEFAULT_AVATAR_URL } from '../constants';
import { toggleLike, createComment, deleteComment, getEffectiveUserId } from '../services/supabaseClient';

interface PostCardProps {
  post: Post;
  isUser: boolean;
  onDelete?: (id: string) => void;
  onTagClick?: (tag: string) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ post, isUser, onDelete, onTagClick }) => {
  const [liked, setLiked] = useState(false);
  const [optimisticLikes, setOptimisticLikes] = useState(post.likes);
  const [isDeleting, setIsDeleting] = useState(false);

  // Comment State
  const [showComments, setShowComments] = useState(false);
  const [comments, setComments] = useState<Comment[]>(post.comments || []);
  const [newCommentText, setNewCommentText] = useState('');
  const [isSubmittingComment, setIsSubmittingComment] = useState(false);
  const [currentUserId, setCurrentUserId] = useState<string | null>(null);

  // Sync props to state if post updates from parent (real-time)
  useEffect(() => {
    setComments(post.comments || []);
  }, [post.comments]);

  useEffect(() => {
    getEffectiveUserId().then(setCurrentUserId);
  }, []);

  const handleLike = () => {
    const isLiking = !liked;
    setLiked(isLiking);
    setOptimisticLikes(prev => isLiking ? prev + 1 : prev - 1);
    toggleLike(post.id, isLiking);
  };

  const handleDelete = () => {
    if (confirm('Are you sure you want to delete this post?') && onDelete) {
      setIsDeleting(true);
      onDelete(post.id);
    }
  };

  const handleTagClick = (tag: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (onTagClick) onTagClick(tag);
  };

  const toggleComments = () => {
    setShowComments(!showComments);
  };

  const handleSubmitComment = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newCommentText.trim()) return;

    const text = newCommentText;
    setNewCommentText(''); // Clear input immediately
    setIsSubmittingComment(true);

    // Get current user nickname from local storage for optimistic update
    const nickname = localStorage.getItem('echo_nickname') || 'Guest';

    // Optimistic Comment
    const tempId = 'temp-' + Date.now();
    const optimisticComment: Comment = {
      id: tempId,
      author: {
        nickname,
        avatarSeed: nickname,
        isAi: false,
        userId: currentUserId || ''
      },
      content: text,
      timestamp: Date.now(),
      likes: 0
    };

    setComments(prev => [...prev, optimisticComment]);
    if (!showComments) setShowComments(true);

    try {
      const realComment = await createComment(post.id, text, nickname);
      // Replace optimistic comment with real one
      setComments(prev => prev.map(c => c.id === tempId ? realComment : c));
    } catch (err) {
      console.error("Failed to submit comment", err);
      alert("Failed to post comment. Please try again.");
      setComments(prev => prev.filter(c => c.id !== tempId));
      setNewCommentText(text); // Restore text
    } finally {
      setIsSubmittingComment(false);
    }
  };

  const handleDeleteComment = async (commentId: string) => {
    if (!confirm("Delete this comment?")) return;

    const previousComments = [...comments];
    setComments(prev => prev.filter(c => c.id !== commentId));

    try {
      await deleteComment(commentId);
    } catch (err) {
      console.error("Failed to delete comment", err);
      alert("Could not delete comment.");
      setComments(previousComments);
    }
  };

  const formattedTime = new Intl.DateTimeFormat('en-US', {
    hour: 'numeric',
    minute: 'numeric',
  }).format(new Date(post.timestamp));

  if (isDeleting) {
    return (
        <div className="p-5 mb-4 rounded-[24px] border border-red-200 bg-red-50 text-red-500 flex items-center justify-center dark:border-red-900/50 dark:bg-red-900/10">
            <span className="text-sm font-medium animate-pulse">Deleting...</span>
        </div>
    );
  }

  return (
    <div className={`
      relative p-5 mb-4 transition-all duration-300
      rounded-[24px] border
      ${isUser 
        ? 'bg-neutral-100 border-neutral-200 text-black dark:bg-[#1A1A1A] dark:border-neutral-700 dark:text-white' 
        : 'bg-white border-neutral-200 text-neutral-800 dark:bg-[#0A0A0A] dark:border-[#1F1F1F] dark:text-neutral-300' 
      }
    `}>
      {/* Header */}
      <div className="flex items-start justify-between mb-4">
        <div className="flex items-center gap-4">
          <img 
            src={DEFAULT_AVATAR_URL(post.author.avatarSeed)} 
            alt={post.author.nickname}
            className="w-10 h-10 rounded-full object-cover grayscale opacity-80 hover:grayscale-0 transition-all border border-neutral-200 dark:border-neutral-800" 
          />
          <div>
            <div className="flex items-center gap-2">
              <span className={`text-base font-medium tracking-wide ${isUser ? 'text-black dark:text-white' : 'text-neutral-900 dark:text-neutral-200'}`}>
                {post.author.nickname}
              </span>
              {post.author.isAi && (
                <span className="text-[10px] px-2 py-0.5 rounded-full bg-black text-white dark:bg-white dark:text-black font-bold tracking-wider">
                  BOT
                </span>
              )}
            </div>
            <span className="text-xs text-neutral-500 dark:text-neutral-500">{formattedTime}</span>
          </div>
        </div>

        {isUser && (
           <button 
             onClick={handleDelete}
             className="text-neutral-400 hover:text-red-600 dark:text-neutral-500 dark:hover:text-red-400 rounded-full p-2 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
             title="Delete Post"
           >
             <Trash2 size={18} />
           </button>
        )}
      </div>

      {/* Content */}
      <div className="mb-4 pl-[56px]">
        <p className="text-base leading-relaxed tracking-wide opacity-90 text-neutral-800 dark:text-neutral-200 whitespace-pre-wrap">
          {post.content}
        </p>
        {post.tags.length > 0 && (
          <div className="flex flex-wrap gap-2 mt-4">
            {post.tags.map(tag => (
              <span 
                key={tag} 
                onClick={(e) => handleTagClick(tag, e)}
                className="px-3 py-1 rounded-lg text-xs font-medium transition-colors cursor-pointer
                           bg-neutral-100 border border-neutral-200 text-neutral-600 hover:bg-neutral-200 hover:text-black hover:border-neutral-300
                           dark:bg-neutral-900 dark:border-neutral-800 dark:text-neutral-400 dark:hover:text-white dark:hover:border-neutral-600"
              >
                #{tag.replace(/^#/, '')}
              </span>
            ))}
          </div>
        )}
      </div>

      {/* Actions */}
      <div className="flex items-center gap-6 pl-[56px] pt-1">
        <button 
          onClick={handleLike}
          className={`group flex items-center gap-2 text-sm font-medium transition-colors 
            ${liked 
              ? 'text-black dark:text-white' 
              : 'text-neutral-500 hover:text-black dark:text-neutral-500 dark:hover:text-neutral-300'
            }`}
        >
          <div className={`p-2 rounded-full group-hover:bg-black/5 dark:group-hover:bg-white/10 transition-colors`}>
             <Heart size={20} fill={liked ? "currentColor" : "none"} className={liked ? "scale-110" : ""} />
          </div>
          <span>{optimisticLikes}</span>
        </button>

        <button 
          onClick={toggleComments}
          className={`group flex items-center gap-2 text-sm font-medium transition-colors
            ${showComments ? 'text-black dark:text-white' : 'text-neutral-500 hover:text-black dark:text-neutral-500 dark:hover:text-white'}
          `}
        >
          <div className="p-2 rounded-full group-hover:bg-black/5 dark:group-hover:bg-white/10 transition-colors">
             <MessageCircle size={20} />
          </div>
          <span>{comments.length}</span>
        </button>

        <button className="group flex items-center gap-2 text-sm font-medium text-neutral-500 hover:text-black dark:text-neutral-500 dark:hover:text-white transition-colors">
           <div className="p-2 rounded-full group-hover:bg-black/5 dark:group-hover:bg-white/10 transition-colors">
              <Share2 size={20} />
           </div>
        </button>
      </div>

      {/* Comments Section */}
      {showComments && (
        <div className="mt-4 pt-4 pl-[56px] border-t border-neutral-100 dark:border-neutral-800 animate-in fade-in slide-in-from-top-2 duration-200">

          {/* Add Comment Input */}
          <form onSubmit={handleSubmitComment} className="flex gap-3 mb-6">
             <img 
                src={DEFAULT_AVATAR_URL(localStorage.getItem('echo_nickname') || 'Guest')} 
                className="w-8 h-8 rounded-full grayscale opacity-50"
             />
             <div className="flex-1 relative">
                <input 
                  type="text" 
                  value={newCommentText}
                  onChange={(e) => setNewCommentText(e.target.value)}
                  placeholder="Write a reply..."
                  className="w-full bg-neutral-50 dark:bg-neutral-900 border border-neutral-200 dark:border-neutral-800 rounded-full py-2 px-4 text-sm focus:outline-none focus:border-black dark:focus:border-white transition-colors"
                />
                <button 
                  type="submit" 
                  disabled={!newCommentText.trim() || isSubmittingComment}
                  className="absolute right-2 top-1.5 p-1 rounded-full text-black dark:text-white hover:bg-neutral-200 dark:hover:bg-neutral-700 disabled:opacity-30 disabled:hover:bg-transparent transition-all"
                >
                  <Send size={14} />
                </button>
             </div>
          </form>

          {/* Comment List */}
          <div className="space-y-5">
            {comments.map(comment => (
              <div key={comment.id} className="flex gap-3 group/comment">
                <img 
                  src={DEFAULT_AVATAR_URL(comment.author.avatarSeed)} 
                  alt={comment.author.nickname}
                  className="w-8 h-8 rounded-full grayscale opacity-70"
                />
                <div className="flex-1">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2 mb-0.5">
                      <span className="text-sm font-bold text-neutral-900 dark:text-neutral-200">{comment.author.nickname}</span>
                      <span className="text-[10px] text-neutral-400 dark:text-neutral-600">
                        {new Intl.DateTimeFormat('en-US', { hour: 'numeric', minute: 'numeric' }).format(new Date(comment.timestamp))}
                      </span>
                    </div>

                    {currentUserId === comment.author.userId && (
                      <button 
                        onClick={() => handleDeleteComment(comment.id)}
                        className="opacity-0 group-hover/comment:opacity-100 transition-opacity p-1 text-neutral-400 hover:text-red-500"
                      >
                        <Trash2 size={12} />
                      </button>
                    )}
                  </div>
                  <p className="text-sm text-neutral-600 dark:text-neutral-400 leading-relaxed">{comment.content}</p>
                </div>
              </div>
            ))}

            {comments.length === 0 && (
                <div className="text-center py-4 opacity-40 text-xs italic">
                    No comments yet. Start the conversation.
                </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Menu, Home, TrendingUp, Sun, Moon, Database, XCircle, Terminal, RefreshCw, Copy, Check, Hash, X, Lock } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { Post } from './types';
import { INITIAL_TOPICS } from './constants';
import * as SupabaseService from './services/supabaseClient';

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);

  const [currentUserNickname, setCurrentUserNickname] = useState<string>(() => {
    if (typeof window !== 'undefined') {
        return localStorage.getItem('echo_nickname') || 'Guest';
    }
    return 'Guest';
  });

  const [authUserId, setAuthUserId] = useState<string | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [copied, setCopied] = useState(false);
  const [selectedTag, setSelectedTag] = useState<string | null>(null);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('echo_theme');
      return saved === 'light' || saved === 'dark' ? saved : 'light';
    }
    return 'light';
  });

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('echo_theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('echo_nickname', currentUserNickname);
  }, [currentUserNickname]);

  // Init Auth and Load Data
  useEffect(() => {
    const init = async () => {
        try {
            setIsAuthLoading(true);
            const uid = await SupabaseService.initializeAuth();
            setAuthUserId(uid);
            await loadPosts();
        } catch (e: any) {
            console.error("Critical Init Failure", e);
            setErrorMsg(getErrorMessage(e));
        } finally {
            setIsAuthLoading(false);
            setIsLoading(false);
        }
    };
    init();
  }, []);

  const getErrorMessage = (e: any) => {
    if (!e) return "Unknown error";
    if (e.code && e.message) return `Error ${e.code}: ${e.message}`;
    if (e.message) return e.message;
    return typeof e === 'string' ? e : JSON.stringify(e);
  };

  const loadPosts = async () => {
    try {
      const remotePosts = await SupabaseService.fetchPosts();
      setPosts(remotePosts);
    } catch (e: any) {
      console.error("Failed to load posts", e);
      if (posts.length === 0) setErrorMsg(getErrorMessage(e));
    }
  };

  useEffect(() => {
    const subscription = SupabaseService.subscribeToPosts((payload) => {
      // Refresh on any insert or delete in posts OR comments
      if (payload.eventType === 'INSERT' || payload.eventType === 'DELETE') {
        loadPosts();
      }
    });
    return () => { subscription?.unsubscribe(); };
  }, []);

  const handleUserPost = async (nickname: string, content: string, tags: string[]) => {
    if (!authUserId) return;
    setCurrentUserNickname(nickname);

    const tempId = Date.now().toString(); 
    const tempPost: Post = {
        id: tempId,
        author: { 
            nickname, 
            avatarSeed: nickname, 
            isAi: false,
            userId: authUserId
        },
        content,
        tags,
        timestamp: Date.now(),
        likes: 0,
        comments: []
    };

    setPosts(prev => [tempPost, ...prev]);

    try {
        const realPost = await SupabaseService.createPost(nickname, content, tags);
        if (realPost) {
            setPosts(prev => prev.map(p => p.id === tempId ? realPost : p));
        }
    } catch (e: any) {
        console.error("Post failed", e);
        setPosts(prev => prev.filter(p => p.id !== tempId)); 
        alert(`Failed to post. Ensure your DB Policies are updated.\n\n${getErrorMessage(e)}`);
    }
  };

  const handleDeletePost = async (postId: string) => {
    setPosts(prev => prev.filter(p => p.id !== postId));

    if (!postId.includes('-') && /^\d+$/.test(postId)) return;

    try {
        await SupabaseService.deletePost(postId);
    } catch (e: any) {
        console.error("Delete failed", e);
        alert(`Failed to delete. You might not be the owner.\n\n${getErrorMessage(e)}`);
        loadPosts();
    }
  };

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const copySQL = () => {
    const sql = `
-- 1. Table Setup: Posts
create table if not exists posts (
  id uuid default gen_random_uuid() primary key,
  nickname text not null,
  content text not null,
  tags text[] default '{}',
  likes int default 0,
  avatar_seed text,
  user_id uuid,
  created_at timestamptz default now()
);

-- 2. Table Setup: Comments
create table if not exists comments (
  id uuid default gen_random_uuid() primary key,
  post_id uuid references posts(id) on delete cascade not null,
  user_id uuid,
  nickname text not null,
  avatar_seed text,
  content text not null,
  created_at timestamptz default now()
);

-- 3. Security Setup
alter table posts enable row level security;
alter table comments enable row level security;
create index if not exists idx_posts_user_id on posts(user_id);

-- 4. Clean old policies
drop policy if exists "Universal Read" on posts;
drop policy if exists "Universal Insert" on posts;
drop policy if exists "Universal Delete" on posts;
drop policy if exists "Universal Read Comments" on comments;
drop policy if exists "Universal Insert Comments" on comments;
drop policy if exists "Universal Delete Comments" on comments;

-- 5. UNIVERSAL POLICIES (POSTS)
create policy "Universal Read" on posts for select using (true);
create policy "Universal Insert" on posts for insert with check (
  (auth.uid() IS NOT NULL AND auth.uid() = user_id) OR
  (auth.uid() IS NULL AND (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)
);
create policy "Universal Delete" on posts for delete using (
  (auth.uid() IS NOT NULL AND auth.uid() = user_id) OR
  (auth.uid() IS NULL AND (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)
);

-- 6. UNIVERSAL POLICIES (COMMENTS)
create policy "Universal Read Comments" on comments for select using (true);
create policy "Universal Insert Comments" on comments for insert with check (
  (auth.uid() IS NOT NULL AND auth.uid() = user_id) OR
  (auth.uid() IS NULL AND (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)
);
create policy "Universal Delete Comments" on comments for delete using (
  (auth.uid() IS NOT NULL AND auth.uid() = user_id) OR
  (auth.uid() IS NULL AND (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)
);
`;

    navigator.clipboard.writeText(sql);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleTagClick = (tag: string) => {
      const rawTag = tag.replace(/^#/, '');
      setSelectedTag(rawTag);
      if (scrollRef.current) scrollRef.current.scrollTop = 0;
  };

  const clearFilter = () => setSelectedTag(null);

  const filteredPosts = useMemo(() => {
      if (!selectedTag) return posts;
      return posts.filter(post => 
          post.tags.some(t => t.toLowerCase() === selectedTag.toLowerCase())
      );
  }, [posts, selectedTag]);

  const activeUsers = useMemo(() => {
    const uniqueUsers = new Map();
    posts.forEach(post => {
      if (!uniqueUsers.has(post.author.nickname)) {
        uniqueUsers.set(post.author.nickname, post.author.avatarSeed);
      }
    });
    return Array.from(uniqueUsers.entries()).map(([nickname, seed]) => ({ nickname, seed }));
  }, [posts]);

  const trendingTopics = useMemo(() => {
    const counts: Record<string, number> = {};
    posts.forEach(post => post.tags.forEach(tag => counts[tag] = (counts[tag] || 0) + 1));
    const sorted = Object.entries(counts).sort((a, b) => b[1] - a[1]);
    return sorted.length > 0 ? sorted.slice(0, 5).map(t => '#' + t[0]) : INITIAL_TOPICS;
  }, [posts]);

  const isOwner = (post: Post) => {
    if (!authUserId) return false;
    return post.author.userId === authUserId;
  };

  return (
    <div className="min-h-screen flex justify-center transition-colors duration-300
                    bg-[#F5F5F5] text-neutral-900
                    dark:bg-[#000000] dark:text-white">

      <div className="flex w-full max-w-7xl h-screen">

        {/* Navigation Rail */}
        <nav className="hidden md:flex flex-col w-20 lg:w-72 shrink-0 pt-8 px-4 transition-colors border-r
                        bg-white border-neutral-200
                        dark:bg-[#000000] dark:border-[#1F1F1F]">

          <div className="mb-8 flex items-center justify-center lg:justify-start lg:pl-4">
             <span className="text-2xl font-bold tracking-tight">Echo</span>
          </div>

          <div className="space-y-2">
            <div onClick={clearFilter} 
                 className={`flex items-center gap-4 px-4 py-4 rounded-full font-bold cursor-pointer transition-transform hover:scale-[1.02]
                            ${!selectedTag ? 'bg-black text-white dark:bg-white dark:text-black' : 'text-neutral-500 hover:bg-neutral-100 dark:hover:bg-[#121212] hover:text-black dark:hover:text-white'}`}>
               <Home size={24} />
               <span className="hidden lg:block">Feed</span>
            </div>

            <div className={`flex items-center gap-4 px-4 py-4 rounded-full cursor-pointer transition-colors
                            ${selectedTag ? 'bg-black text-white dark:bg-white dark:text-black' : 'text-neutral-500 hover:bg-neutral-100 dark:hover:bg-[#121212] hover:text-black dark:hover:text-white'}`}>
               <TrendingUp size={24} />
               <span className="hidden lg:block">Trending</span>
            </div>

            <button onClick={toggleTheme}
               className="flex items-center gap-4 px-4 py-4 rounded-full cursor-pointer transition-colors w-full text-left
                          text-neutral-500 hover:bg-neutral-100 hover:text-black
                          dark:text-neutral-500 dark:hover:bg-[#121212] dark:hover:text-white">
               {theme === 'dark' ? <Sun size={24} /> : <Moon size={24} />}
               <span className="hidden lg:block">{theme === 'dark' ? 'Light Mode' : 'Dark Mode'}</span>
            </button>
          </div>

          <div className="mt-auto mb-8 hidden lg:block">
            <div className="p-4 rounded-[24px] border
                            bg-neutral-50 border-neutral-200
                            dark:bg-[#0A0A0A] dark:border-[#1F1F1F]">
              <h3 className="text-sm font-semibold mb-4 text-neutral-500 dark:text-neutral-400">Trending Now</h3>
              <div className="flex flex-wrap gap-2">
                {trendingTopics.map((topic, i) => (
                  <span key={i} 
                        onClick={() => handleTagClick(topic)}
                        className={`text-xs px-2 py-1 rounded-md cursor-pointer transition-colors
                                   ${selectedTag && topic.toLowerCase().includes(selectedTag.toLowerCase()) 
                                        ? 'bg-black text-white dark:bg-white dark:text-black' 
                                        : 'bg-white text-neutral-700 hover:bg-black hover:text-white dark:bg-[#1F1F1F] dark:text-neutral-300 dark:hover:bg-white dark:hover:text-black'
                                   }`}>
                      {topic}
                  </span>
                ))}
              </div>
            </div>

            <button 
                onClick={copySQL}
                className="mt-4 flex items-center gap-2 text-xs text-neutral-400 hover:text-black dark:hover:text-white transition-colors"
            >
                <Database size={12} />
                <span>Fix Database (Posts + Comments)</span>
                {copied ? <Check size={12} className="text-green-500" /> : null}
            </button>
          </div>
        </nav>

        {/* Main Content Area */}
        <main className="flex-1 flex flex-col h-full relative max-w-2xl mx-auto w-full">
          {/* Mobile Header */}
          <div className="md:hidden flex items-center justify-between p-4 border-b sticky top-0 z-20 transition-colors
                          bg-white border-neutral-200 text-black
                          dark:bg-[#000000] dark:border-[#1F1F1F] dark:text-white">
             <div className="flex items-center gap-2">
               <span onClick={clearFilter} className="text-xl font-bold tracking-tight cursor-pointer">Echo</span>
             </div>
             <div className="flex gap-2">
                <button onClick={toggleTheme} className="p-2">
                  {theme === 'dark' ? <Sun size={24} /> : <Moon size={24} />}
                </button>
             </div>
          </div>

          <div 
            ref={scrollRef}
            className="flex-1 overflow-y-auto px-4 py-6 scroll-smooth"
          >
             <div className="max-w-xl mx-auto">

                {/* Error Banner & Setup Instructions */}
                {errorMsg && (
                    <div className="mb-6 p-4 rounded-xl border border-red-200 bg-red-50 text-red-800 dark:border-red-900/50 dark:bg-red-900/20 dark:text-red-200 shadow-sm">
                        <div className="flex items-start gap-3">
                            <XCircle className="shrink-0 mt-0.5" size={20} />
                            <div className="space-y-3 w-full">
                                <div>
                                    <h3 className="font-bold text-sm">Connection Error</h3>
                                    <p className="text-xs opacity-90 font-mono break-all whitespace-pre-wrap">{errorMsg}</p>
                                </div>

                                <div className="p-3 bg-white dark:bg-black rounded-lg border border-red-100 dark:border-red-900/30">
                                    <div className="flex items-center justify-between mb-2">
                                        <div className="flex items-center gap-2">
                                            <Terminal size={14} />
                                            <span className="text-xs font-bold uppercase">Setup Required</span>
                                        </div>
                                        <button 
                                            onClick={copySQL}
                                            className="flex items-center gap-1 text-[10px] uppercase font-bold tracking-wider hover:text-black dark:hover:text-white transition-colors"
                                        >
                                            {copied ? <Check size={12} className="text-green-500" /> : <Copy size={12} />}
                                            {copied ? 'Copied' : 'Copy SQL'}
                                        </button>
                                    </div>
                                    <p className="text-[11px] mb-2 opacity-80">
                                        Run this SQL to enable <b>Universal Access</b> (fixes both Anon Auth and Shadow Identity issues):
                                    </p>
                                    <code className="block text-[10px] font-mono p-3 bg-neutral-100 dark:bg-[#1A1A1A] rounded overflow-x-auto text-neutral-600 dark:text-neutral-400 select-all">
                                        -- See Clipboard for full SQL --<br/>
                                        create policy "Universal Insert" on posts...
                                    </code>
                                </div>

                                <button 
                                  onClick={() => window.location.reload()} 
                                  className="text-xs font-medium underline flex items-center gap-1 hover:text-red-600"
                                >
                                  <RefreshCw size={12} /> Reload
                                </button>
                            </div>
                        </div>
                    </div>
                )}

                {/* Filter Banner */}
                {selectedTag && (
                    <div className="mb-6 flex items-center justify-between p-4 rounded-[24px] border
                                    bg-black text-white
                                    dark:bg-white dark:text-black">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-full bg-white/20 dark:bg-black/10">
                                <Hash size={20} />
                            </div>
                            <div>
                                <h3 className="font-bold text-sm">#{selectedTag}</h3>
                                <p className="text-xs opacity-80">Viewing filtered posts</p>
                            </div>
                        </div>
                        <button onClick={clearFilter} className="p-2 rounded-full hover:bg-white/20 dark:hover:bg-black/10 transition-colors">
                            <X size={20} />
                        </button>
                    </div>
                )}

                {!selectedTag && !isAuthLoading && (
                    <CreatePost onPost={handleUserPost} defaultNickname={currentUserNickname} />
                )}

                <div className="space-y-2">
                    {filteredPosts.length === 0 && !isLoading && !errorMsg ? (
                        <div className="text-center py-32 opacity-50">
                            <div className="text-6xl mb-4 grayscale filter contrast-200">
                                {selectedTag ? '🔍' : '🌍'}
                            </div>
                            <h2 className="text-xl font-medium mb-2">
                                {selectedTag ? 'No posts found' : 'World is Quiet'}
                            </h2>
                            <p className="text-sm text-neutral-500">
                                {selectedTag ? `Nobody has posted about #${selectedTag} yet.` : 'Be the first to post something.'}
                            </p>
                            {selectedTag && (
                                <button onClick={clearFilter} className="mt-4 text-sm font-bold underline hover:text-black dark:hover:text-white">
                                    Clear Filter
                                </button>
                            )}
                        </div>
                    ) : (
                        filteredPosts.map(post => (
                            <PostCard 
                                key={post.id} 
                                post={post} 
                                isUser={isOwner(post)} 
                                onDelete={handleDeletePost}
                                onTagClick={handleTagClick}
                            />
                        ))
                    )}

                    {(isLoading || isAuthLoading) && posts.length === 0 && (
                         <div className="text-center py-32 opacity-50 animate-pulse">
                            <div className="text-4xl mb-4">...</div>
                            <p className="text-sm">Connecting to global feed...</p>
                         </div>
                    )}
                </div>

                <div className="h-20 flex items-center justify-center gap-2 text-xs text-neutral-400">
                    <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                    Live • Limited to {SupabaseService.MAX_POSTS_LIMIT} posts
                </div>
             </div>
          </div>
        </main>

        {/* Right Sidebar - Status */}
        <aside className="hidden xl:flex flex-col w-80 shrink-0 border-l pt-8 px-6 transition-colors
                          bg-white border-neutral-200
                          dark:bg-[#000000] dark:border-[#1F1F1F]">

            <div className="mb-6">
                <h3 className="text-lg font-medium mb-4 px-2 text-neutral-800 dark:text-neutral-200">Contributors</h3>
                <div className="space-y-2">
                    {activeUsers.slice(0, 8).map((user, i) => (
                        <div key={i} className="flex items-center gap-3 p-3 rounded-full cursor-pointer transition-colors group hover:bg-neutral-100 dark:hover:bg-[#121212]">
                            <img src={`https://api.dicebear.com/7.x/notionists/svg?seed=${user.seed}&backgroundColor=e4e2e2`} className="w-8 h-8 rounded-full" />
                            <div className="text-sm font-medium opacity-70 group-hover:opacity-100">@{user.nickname}</div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="mt-auto mb-8 p-4 rounded-[24px] border text-sm leading-relaxed
                            bg-neutral-50 border-neutral-200 text-neutral-600
                            dark:bg-[#0A0A0A] dark:border-[#1F1F1F] dark:text-neutral-400">
               <div className="flex items-center gap-2 mb-2 font-semibold text-black dark:text-white">
                   <Lock size={16} />
                   <span>Security Status</span>
               </div>

               <div className="space-y-3">
                    {/* Visual indicator for Auth Status */}
                    {authUserId && !authUserId.includes('-') && authUserId.length > 30 ? (
                        <div className="flex items-center gap-2 text-green-600 dark:text-green-400">
                            <div className="w-2 h-2 rounded-full bg-current"></div>
                            <span className="font-medium text-xs">Standard Auth (JWT)</span>
                        </div>
                    ) : (
                         <div className="flex items-center gap-2 text-yellow-500">
                            <div className="w-2 h-2 rounded-full bg-current"></div>
                            <span className="font-medium text-xs">Shadow Mode (Fallback)</span>
                        </div>
                    )}

                    <p className="opacity-70 text-xs font-mono break-all">
                       {authUserId ? `UID: ${authUserId.slice(0,8)}...` : 'Connecting...'}
                    </p>

                    {errorMsg && !authUserId && (
                         <p className="text-[10px] text-red-500 mt-2 leading-tight">
                            Issues detected. Check console.
                         </p>
                    )}
               </div>
            </div>
        </aside>

      </div>
    </div>
  );
}
